-- ============================================================
-- Migration 016 — Section 5 content (Locational Influence)
-- Bulk-loads M2-S5-C5 (Government & Public Use) and M2-S5-C6
-- (Specialty Situations), 10 scenarios per category, 20 total.
--
-- This is Session 4 of 4 — the final session for Section 5.
-- After this migration, Section 5 is 100% complete:
--   60 scenarios across all 6 categories.
--
-- Difficulty distribution (per category):
--   #1, #2  · introductory
--   #3, #4  · basic
--   #5, #6  · intermediate
--   #7, #8  · advanced
--   #9, #10 · expert
--
-- Section 5 final state after this migration:
--   - M2-S5-C1 (Mortgage Lending) — 10 scenarios (migration 014)
--   - M2-S5-C2 (Litigation Support) — 10 scenarios (migration 014)
--   - M2-S5-C3 (Estate & Tax) — 10 scenarios (migration 015)
--   - M2-S5-C4 (Private/Consulting) — 10 scenarios (migration 015)
--   - M2-S5-C5 (Government & Public Use) — 10 scenarios (this)
--   - M2-S5-C6 (Specialty Situations) — 10 scenarios (this)
--
-- No schema changes. The factor_analysis field type and the six
-- M2-S5 categories were created in Session 1 (migration 013).
-- Section-level defaults from Session 1:
--   classification_options = ['Positive','Negative','Neutral','Market-Dependent']
--   min_rationale_chars    = 20
-- These are repeated explicitly in each field_options_override
-- for self-describing scenario rows.
--
-- C5 scenarios cover VA, FHA, and SCDOT condemnation assignments —
-- a heterogeneous category unified by the dual-lens analytical
-- requirement (market value AND program-specific compliance).
-- context_label = 'Government Context'.
--
-- C6 scenarios cover waterfront tiers, ADU, STR, mountain markets,
-- and combined specialty configurations. Scenario #10 (Keowee
-- Peninsula Club) has 13 factors (A through M) — the most of any
-- scenario in Section 5, with four interacting specialty
-- characteristics. context_label = 'Specialty Context'.
--
-- Idempotency: this migration runs once and is recorded in the
-- migration tracker by the migration runner.
-- ============================================================

BEGIN;

-- ============================================================
-- M2-S5-C5 — Government & Public Use (10 scenarios)
-- ============================================================

-- ─────────────────────────────────────────────────────
-- Scenario 1: 318 Patriot Way, Simpsonville — VA Purchase, Cul-de-Sac Compliant Profile
-- Category M2-S5-C5 #1 · difficulty 'introductory'
-- ─────────────────────────────────────────────────────
INSERT INTO scenarios
  (category_id, order_index, difficulty, title, scenario_text)
SELECT id, 1,
  'introductory',
  '318 Patriot Way, Simpsonville — VA Purchase, Cul-de-Sac Compliant Profile',
  'You are performing a government locational analysis at 318 Patriot Way, Simpsonville, SC 29681. The subject is 3BR/2BA · 1,920 SF · 2011-built SFR · Patriot Estates. VA purchase appraisal. Veteran borrower. Lender: First Reliance Bank. VA Minimum Property Requirements (MPRs) apply in addition to standard market analysis. The appraiser must identify and classify all locational factors and flag any condition that may affect VA eligibility or require underwriter attention. Section 5 — Locational Influence — requires you to identify which locational factors are present at the subject, classify each as Positive, Negative, Neutral, or Market-Dependent based on the location profile evidence, and write a brief market-supported rationale for each classification. Government appraisals require dual-lens analysis: each factor must be evaluated for both market value impact and program-specific compliance implications (VA MPRs, HUD Handbook 4000.1, condemnation before-condition, etc.). Distractor factors that are not present must be left unchecked, and each rationale must cite specific evidence from the location profile and address any compliance implications relevant to this assignment type.'
FROM scenario_categories WHERE code = 'M2-S5-C5';

INSERT INTO model_answers
  (scenario_id, field_id, answer_text, field_options_override, model_data)
SELECT
  s.id,
  f.id,
  '',
  '{"subject": {"address_summary": "318 Patriot Way, Simpsonville, SC 29681", "subject_summary": "3BR/2BA · 1,920 SF · 2011-built SFR · Patriot Estates", "context_label": "Government Context", "context_text": "VA purchase appraisal. Veteran borrower. Lender: First Reliance Bank. VA Minimum Property Requirements (MPRs) apply in addition to standard market analysis. The appraiser must identify and classify all locational factors and flag any condition that may affect VA eligibility or require underwriter attention."}, "location_profile": ["Patriot Estates is a residential subdivision of approximately 200 homes in Simpsonville, southern Greenville County, developed 2008–2015. Lots average 0.24 acres with a loop street pattern and multiple cul-de-sac fingers. The HOA maintains a community greenspace near the entrance. Homes are owner-occupied and well-maintained with no observable deferred maintenance at a neighborhood level.", "318 Patriot Way is a cul-de-sac lot backing to a maintained HOA buffer that screens the subject from a grocery-anchored shopping center approximately 280 feet west. An 8-foot evergreen hedge eliminates rear visibility of the commercial use and no noise is audible from the rear yard. The subject is in the Simpsonville/Hillcrest school attendance zone — a documented market preference driver. FEMA Zone X is confirmed for the entire lot and structure. No environmental hazards, airport noise contours, or high-voltage transmission easements are present within the subject''s immediate area."], "factors": [{"id": "A", "label": "Cul-de-sac location"}, {"id": "B", "label": "Backing to HOA buffer (commercial screened)"}, {"id": "C", "label": "Proximity to retail/commercial use (screened, ~280 ft)"}, {"id": "D", "label": "Desirable school district (Simpsonville/Hillcrest)"}, {"id": "E", "label": "FEMA Zone X (entire lot and structure)"}, {"id": "F", "label": "FEMA Zone AE (flood hazard)"}, {"id": "G", "label": "Airport noise contour / flight path"}], "classification_options": ["Positive", "Negative", "Neutral", "Market-Dependent"], "min_rationale_chars": 20, "teaching_points": ["Teaching Point 1 — VA appraisals require dual-lens analysis. The appraiser must simultaneously address market factors and VA MPR compliance. In this introductory scenario, no MPR issues are present — but the discipline of checking for them (flood zone, environmental hazards, noise contours, safety concerns) is itself a required step. Students must develop the habit of explicitly confirming MPR status for each relevant category, not merely assuming compliance.", "Teaching Point 2 — Zone X confirmation is a positive condition in government lending. Factor E is Positive not only as a market factor (no flood insurance cost) but as a VA underwriting condition (Zone X properties have no mandatory flood insurance requirement). Government appraisers must understand that the same locational condition carries analytical weight in two separate frameworks simultaneously.", "Teaching Point 3 — Distractors test government-context pattern recognition. Zone AE (F) and airport noise contour (G) are both conditions that would trigger specific VA MPR review if present. Including them as distractors tests whether students apply government-context awareness to their identification — recognizing that in a VA assignment, these are the highest-stakes factors to check first."]}'::jsonb,
  '{"factors": {"A": {"present": true, "classification": "Positive", "rationale": "Cul-de-sac terminus with minimal through-traffic — a consistently preferred configuration. No VA MPR implications; a straightforward market-positive locational attribute."}, "B": {"present": true, "classification": "Positive", "rationale": "HOA-maintained buffer with mature evergreen screening eliminates commercial visibility and noise — a positive locational attribute with no VA eligibility concerns."}, "C": {"present": true, "classification": "Neutral", "rationale": "Commercial presence is documented but physically mitigated. Must be identified and noted in the report; no VA MPR concern at this distance with full screening."}, "D": {"present": true, "classification": "Positive", "rationale": "Documented buyer preference driver in this submarket — a market-supported Positive. School district is not a VA eligibility criterion but supports overall marketability."}, "E": {"present": true, "classification": "Positive", "rationale": "Zone X confirmed for the full lot — no flood insurance requirement under VA lending guidelines. A positive condition for both market analysis and VA underwriting."}, "F": {"present": false}, "G": {"present": false}}}'::jsonb
FROM scenarios s
JOIN scenario_categories sc ON sc.id = s.category_id
JOIN module_sections ms ON ms.id = sc.section_id
JOIN section_fields f ON f.section_id = ms.id AND f.field_key = 'factor_analysis'
WHERE sc.code = 'M2-S5-C5'
  AND s.order_index = 1;

-- ─────────────────────────────────────────────────────
-- Scenario 2: 847 Homestead Drive, Greer — FHA Purchase, BMW Submarket
-- Category M2-S5-C5 #2 · difficulty 'introductory'
-- ─────────────────────────────────────────────────────
INSERT INTO scenarios
  (category_id, order_index, difficulty, title, scenario_text)
SELECT id, 2,
  'introductory',
  '847 Homestead Drive, Greer — FHA Purchase, BMW Submarket',
  'You are performing a government locational analysis at 847 Homestead Drive, Greer, SC 29651. The subject is 3BR/2BA · 1,780 SF · 2008-built SFR · Homestead Commons. FHA purchase appraisal. First-time homebuyer using FHA financing. Lender: Carolina First Mortgage. FHA/HUD appraisal requirements apply. The appraiser must identify locational factors affecting both market value and FHA eligibility, including any conditions requiring notation in the appraisal report under HUD handbook requirements. Section 5 — Locational Influence — requires you to identify which locational factors are present at the subject, classify each as Positive, Negative, Neutral, or Market-Dependent based on the location profile evidence, and write a brief market-supported rationale for each classification. Government appraisals require dual-lens analysis: each factor must be evaluated for both market value impact and program-specific compliance implications (VA MPRs, HUD Handbook 4000.1, condemnation before-condition, etc.). Distractor factors that are not present must be left unchecked, and each rationale must cite specific evidence from the location profile and address any compliance implications relevant to this assignment type.'
FROM scenario_categories WHERE code = 'M2-S5-C5';

INSERT INTO model_answers
  (scenario_id, field_id, answer_text, field_options_override, model_data)
SELECT
  s.id,
  f.id,
  '',
  '{"subject": {"address_summary": "847 Homestead Drive, Greer, SC 29651", "subject_summary": "3BR/2BA · 1,780 SF · 2008-built SFR · Homestead Commons", "context_label": "Government Context", "context_text": "FHA purchase appraisal. First-time homebuyer using FHA financing. Lender: Carolina First Mortgage. FHA/HUD appraisal requirements apply. The appraiser must identify locational factors affecting both market value and FHA eligibility, including any conditions requiring notation in the appraisal report under HUD handbook requirements."}, "location_profile": ["Homestead Commons is a residential subdivision of approximately 180 homes in Greer, northern Greenville County, developed 2004–2011. The neighborhood has loop streets with no cul-de-sacs. Homes are owner-occupied with some deferred maintenance on older units at the subdivision perimeter. An HOA governs exterior maintenance standards with dues of $95/month.", "847 Homestead Drive is a through-street midblock lot of 0.21 acres with a 32-foot setback from Homestead Drive, which carries light residential traffic. The subject is in the Greer/Eastside school attendance zone, above-average in Greenville County with documented positive buyer reception. FEMA Zone X is confirmed for the entire lot. BMW Manufacturing is approximately 4 miles south — a documented employment demand driver in this submarket. No environmental hazards, underground storage tanks, or high-voltage easements are identified within the subject''s immediate area. The nearest commercial use is a pharmacy 0.6 miles north with no direct impact on the subject."], "factors": [{"id": "A", "label": "Through-street location (light residential traffic)"}, {"id": "B", "label": "HOA with $95/month dues and maintenance standards"}, {"id": "C", "label": "Greer/Eastside school district (above average)"}, {"id": "D", "label": "BMW Manufacturing employment proximity (~4 miles)"}, {"id": "E", "label": "FEMA Zone X (entire lot)"}, {"id": "F", "label": "FEMA Zone AE"}, {"id": "G", "label": "Environmental hazard or underground storage tank proximity"}], "classification_options": ["Positive", "Negative", "Neutral", "Market-Dependent"], "min_rationale_chars": 20, "teaching_points": ["Teaching Point 1 — FHA marketability is a dual requirement. FHA appraisers must address both market value and marketability under HUD handbook standards. Marketability means the property must be acceptable to the general market — not just the specific buyer. Factors that constrain the general buyer pool (through-street, HOA dues, below-average school zone) affect FHA marketability analysis even when they do not trigger specific MPR conditions.", "Teaching Point 2 — HOA compliance is a distinct FHA underwriting consideration. Factor B involves not just the market impact of HOA dues but the FHA requirement that the HOA be in good standing (no litigation, adequate reserves, no owner-occupancy ratio concerns). Students working in FHA contexts must recognize that the Market-Dependent locational classification triggers additional FHA underwriting review beyond the appraisal itself.", "Teaching Point 3 — Environmental hazard distractor (G). The absence of underground storage tanks and environmental hazards must be confirmed, not merely assumed. Students who omit the confirmation step because nothing was found are skipping an MPR verification that the FHA appraiser is obligated to perform and document. Negative findings are still findings."]}'::jsonb,
  '{"factors": {"A": {"present": true, "classification": "Negative", "rationale": "Through-street with light residential traffic is a modest Negative relative to lower-traffic configurations — no FHA MPR concern but a market factor that must be identified."}, "B": {"present": true, "classification": "Market-Dependent", "rationale": "HOA dues at $95/month represent a carrying cost that produces split buyer response. Market-Dependent is appropriate; FHA financing is permitted in HOA communities subject to standard underwriting review."}, "C": {"present": true, "classification": "Positive", "rationale": "Above-average district with documented positive buyer reception — a market-supported Positive. School quality supports overall FHA marketability though it is not a standalone FHA eligibility factor."}, "D": {"present": true, "classification": "Positive", "rationale": "BMW employment proximity is a documented demand driver in the Greer submarket — a Positive supporting both market value and FHA appraisal marketability."}, "E": {"present": true, "classification": "Positive", "rationale": "Zone X confirmed — no mandatory flood insurance requirement under FHA/HUD guidelines. A positive condition for both market analysis and FHA underwriting review."}, "F": {"present": false}, "G": {"present": false}}}'::jsonb
FROM scenarios s
JOIN scenario_categories sc ON sc.id = s.category_id
JOIN module_sections ms ON ms.id = sc.section_id
JOIN section_fields f ON f.section_id = ms.id AND f.field_key = 'factor_analysis'
WHERE sc.code = 'M2-S5-C5'
  AND s.order_index = 2;

-- ─────────────────────────────────────────────────────
-- Scenario 3: 1205 Riverside Court, Spartanburg — VA Purchase, Partial Zone AE Lot
-- Category M2-S5-C5 #3 · difficulty 'basic'
-- ─────────────────────────────────────────────────────
INSERT INTO scenarios
  (category_id, order_index, difficulty, title, scenario_text)
SELECT id, 3,
  'basic',
  '1205 Riverside Court, Spartanburg — VA Purchase, Partial Zone AE Lot',
  'You are performing a government locational analysis at 1205 Riverside Court, Spartanburg, SC 29301. The subject is 3BR/2BA · 1,740 SF · 2009-built SFR · Riverside Crossing. VA purchase appraisal. Active duty borrower stationed at a regional National Guard facility. Lender: Veterans United. VA MPRs apply. A FEMA flood map review reveals that the rear portion of the subject lot falls within Zone AE — the 100-year floodplain — while the structure and primary yard are in Zone X. This condition requires specific notation and analysis under VA lending guidelines. Section 5 — Locational Influence — requires you to identify which locational factors are present at the subject, classify each as Positive, Negative, Neutral, or Market-Dependent based on the location profile evidence, and write a brief market-supported rationale for each classification. Government appraisals require dual-lens analysis: each factor must be evaluated for both market value impact and program-specific compliance implications (VA MPRs, HUD Handbook 4000.1, condemnation before-condition, etc.). Distractor factors that are not present must be left unchecked, and each rationale must cite specific evidence from the location profile and address any compliance implications relevant to this assignment type.'
FROM scenario_categories WHERE code = 'M2-S5-C5';

INSERT INTO model_answers
  (scenario_id, field_id, answer_text, field_options_override, model_data)
SELECT
  s.id,
  f.id,
  '',
  '{"subject": {"address_summary": "1205 Riverside Court, Spartanburg, SC 29301", "subject_summary": "3BR/2BA · 1,740 SF · 2009-built SFR · Riverside Crossing", "context_label": "Government Context", "context_text": "VA purchase appraisal. Active duty borrower stationed at a regional National Guard facility. Lender: Veterans United. VA MPRs apply. A FEMA flood map review reveals that the rear portion of the subject lot falls within Zone AE — the 100-year floodplain — while the structure and primary yard are in Zone X. This condition requires specific notation and analysis under VA lending guidelines."}, "location_profile": ["Riverside Crossing is a residential subdivision of approximately 150 homes in Spartanburg, developed 2005–2012, along a creek corridor in western Spartanburg County. Lots near the creek are subject to variable FEMA flood designations. The subdivision has a loop street pattern with cul-de-sac fingers extending toward the creek.", "1205 Riverside Court is a cul-de-sac lot. FEMA map review confirms Zone X for the structure and primary yard; Zone AE begins approximately 28 feet behind the rear building line. Periodic standing water is observable in the rear yard after heavy rainfall. Flood insurance is required by VA lending guidelines because Zone AE is present on any portion of the lot. The subject is in the Boiling Springs school district — consistently rated among the top districts in Spartanburg County. An HOA-maintained common area borders the subdivision''s eastern edge with a community walking path. FEMA Zone X covers the structure; Zone AE covers the rear lot area."], "factors": [{"id": "A", "label": "FEMA Zone AE (rear lot portion — triggers VA flood insurance requirement)"}, {"id": "B", "label": "Cul-de-sac location"}, {"id": "C", "label": "Boiling Springs school district (top-rated in county)"}, {"id": "D", "label": "HOA common area and walking path (eastern edge)"}, {"id": "E", "label": "Periodic rear yard standing water (observable drainage issue)"}, {"id": "F", "label": "FEMA Zone X (structure and primary yard)"}, {"id": "G", "label": "Natural lake or scenic water amenity"}, {"id": "H", "label": "Airport noise contour"}], "classification_options": ["Positive", "Negative", "Neutral", "Market-Dependent"], "min_rationale_chars": 20, "teaching_points": ["Teaching Point 1 — Zone AE on any lot portion triggers VA flood insurance regardless of structure location. Factor A is the central teaching point of this scenario. Students who classify Zone AE as Neutral because the structure is in Zone X are misapplying VA MPR requirements. VA guidelines require flood insurance whenever Zone AE appears anywhere on the lot — the structure location is irrelevant to the insurance trigger.", "Teaching Point 2 — Standing water and Zone AE are analytically distinct factors. Factor E (standing water) and Factor A (Zone AE) both relate to drainage and flood risk but are separate factors addressing different concerns. Factor A is a regulatory designation with specific VA lending consequences; Factor E is an observable physical condition that raises VA MPR drainage adequacy concerns independently. Both must be identified and addressed separately in the VA appraisal report.", "Teaching Point 3 — Zone X for the structure (Factor F) is a partial positive, not a mitigation. Factor F must still be identified as Positive because Zone X for the structure is a genuine positive condition — it reduces the flood risk to the structure itself. But students must not allow Factor F to override or soften Factor A in their analysis. A partial Zone X designation does not eliminate the VA flood insurance requirement triggered by Zone AE on the lot."]}'::jsonb,
  '{"factors": {"A": {"present": true, "classification": "Negative", "rationale": "Zone AE on any portion of the lot triggers mandatory flood insurance under VA MPRs regardless of structure location in Zone X. Standing water in the rear yard compounds the practical negative impact on lot usability and buyer perception."}, "B": {"present": true, "classification": "Positive", "rationale": "Cul-de-sac terminus with minimal through-traffic — a consistently preferred market configuration with no adverse VA MPR implications."}, "C": {"present": true, "classification": "Positive", "rationale": "Top-rated in Spartanburg County with documented buyer preference — a market-supported Positive supporting overall VA appraisal marketability."}, "D": {"present": true, "classification": "Positive", "rationale": "HOA-maintained community amenity providing open space and recreational access — a positive locational attribute with no VA eligibility concerns."}, "E": {"present": true, "classification": "Negative", "rationale": "Observable standing water in the rear yard is both a market negative (limited lot utility) and a potential VA MPR concern requiring appraiser notation regarding drainage adequacy."}, "F": {"present": true, "classification": "Positive", "rationale": "Zone X for the structure is a partial positive — but it does not override the Zone AE designation on the rear lot portion for flood insurance purposes under VA guidelines."}, "G": {"present": false}, "H": {"present": false}}}'::jsonb
FROM scenarios s
JOIN scenario_categories sc ON sc.id = s.category_id
JOIN module_sections ms ON ms.id = sc.section_id
JOIN section_fields f ON f.section_id = ms.id AND f.field_key = 'factor_analysis'
WHERE sc.code = 'M2-S5-C5'
  AND s.order_index = 3;

