-- Scenario 4: 412 Millwood Drive, Duncan — FHA Purchase, UST Within 300 ft
-- Category M2-S5-C5 #4 · difficulty 'basic'
-- ─────────────────────────────────────────────────────
INSERT INTO scenarios
  (category_id, order_index, difficulty, title, scenario_text)
SELECT id, 4,
  'basic',
  '412 Millwood Drive, Duncan — FHA Purchase, UST Within 300 ft',
  'You are performing a government locational analysis at 412 Millwood Drive, Duncan, SC 29334. The subject is 3BR/2BA · 1,680 SF · 2006-built SFR · Millwood Ridge. FHA purchase appraisal. First-time homebuyer. Lender: SC Federal Credit Union. FHA/HUD Handbook 4000.1 applies. A gas station with an active underground storage tank (UST) registration operates approximately 220 feet from the subject property. HUD Handbook 4000.1 requires appraisers to identify and note proximity to hazardous materials sites; properties within 300 feet of a UST are subject to additional review. Section 5 — Locational Influence — requires you to identify which locational factors are present at the subject, classify each as Positive, Negative, Neutral, or Market-Dependent based on the location profile evidence, and write a brief market-supported rationale for each classification. Government appraisals require dual-lens analysis: each factor must be evaluated for both market value impact and program-specific compliance implications (VA MPRs, HUD Handbook 4000.1, condemnation before-condition, etc.). Distractor factors that are not present must be left unchecked, and each rationale must cite specific evidence from the location profile and address any compliance implications relevant to this assignment type.'
FROM scenario_categories WHERE code = 'M2-S5-C5';

INSERT INTO model_answers
  (scenario_id, field_id, answer_text, field_options_override, model_data)
SELECT
  s.id,
  f.id,
  '',
  '{"subject": {"address_summary": "412 Millwood Drive, Duncan, SC 29334", "subject_summary": "3BR/2BA · 1,680 SF · 2006-built SFR · Millwood Ridge", "context_label": "Government Context", "context_text": "FHA purchase appraisal. First-time homebuyer. Lender: SC Federal Credit Union. FHA/HUD Handbook 4000.1 applies. A gas station with an active underground storage tank (UST) registration operates approximately 220 feet from the subject property. HUD Handbook 4000.1 requires appraisers to identify and note proximity to hazardous materials sites; properties within 300 feet of a UST are subject to additional review."}, "location_profile": ["Millwood Ridge is a residential subdivision of approximately 160 homes in Duncan, Spartanburg County, developed 2003–2010. Streets form a loop pattern with cul-de-sac fingers. The subdivision has an HOA maintaining entrance landscaping. A QT convenience store and gas station with a documented active UST registration under SCDHEC records is located approximately 220 feet from the subject at the corner of Millwood Road and SC-9.", "412 Millwood Drive is a through-street lot of 0.22 acres. The gas station is visible from the subject''s front yard; no subsurface contamination has been documented at this site in SCDHEC records as of the effective date, but the active UST registration is confirmed. The subject is in the Boiling Springs school district, top-rated in Spartanburg County. SC-9 provides regional access to Spartanburg and I-85 approximately 0.4 miles away. FEMA Zone X is confirmed for the entire lot. No other environmental hazards, noise contours, or high-voltage easements are identified."], "factors": [{"id": "A", "label": "Underground storage tank (UST) within 300 ft — active SCDHEC registration (~220 ft)"}, {"id": "B", "label": "Gas station visibility and traffic (QT, ~220 ft, front yard visible)"}, {"id": "C", "label": "Boiling Springs school district (top-rated in county)"}, {"id": "D", "label": "SC-9 regional road access (0.4 miles)"}, {"id": "E", "label": "FEMA Zone X"}, {"id": "F", "label": "Railroad proximity"}, {"id": "G", "label": "Airport noise contour"}, {"id": "H", "label": "FEMA Zone AE"}], "classification_options": ["Positive", "Negative", "Neutral", "Market-Dependent"], "min_rationale_chars": 20, "teaching_points": ["Teaching Point 1 — UST proximity and commercial nuisance are analytically distinct factors. Factor A (UST/HUD Handbook requirement) and Factor B (gas station proximity externality) both relate to the same gas station but address different concerns. Factor A is a regulatory issue with specific FHA eligibility consequences; Factor B is a standard market externality affecting buyer pool depth. Students must identify both independently — collapsing them into one factor loses the distinction that FHA underwriters require.", "Teaching Point 2 — Absence of documented contamination does not eliminate the UST concern. Factor A is Negative because the active UST registration exists, regardless of whether contamination has been documented. HUD Handbook 4000.1 requires appraiser notation when a UST is within 300 feet — documented contamination triggers a much more serious eligibility concern, but the registration alone is sufficient to require notation and potential further review. Students who classify Factor A as Neutral because no contamination is documented are misapplying the HUD standard.", "Teaching Point 3 — Government appraisals require active hazard investigation. FHA appraisers are required to investigate the immediate area for environmental hazards as part of the appraisal process — they cannot rely solely on what is visible during the inspection. Students who would miss Factor A because it requires SCDHEC record review rather than visual observation are failing a fundamental scope of work obligation in government appraisal assignments."]}'::jsonb,
  '{"factors": {"A": {"present": true, "classification": "Negative", "rationale": "HUD Handbook 4000.1 requires notation and potential further review for properties within 300 feet of an active UST. The proximity is a Negative affecting both FHA eligibility review and market buyer pool depth, as informed buyers recognize the hazard disclosure requirement."}, "B": {"present": true, "classification": "Negative", "rationale": "The gas station at 220 feet is visible from the front yard — a proximity externality generating traffic, noise, and commercial character concerns that reduce residential buyer appeal independently of the UST concern."}, "C": {"present": true, "classification": "Positive", "rationale": "Top-rated district in Spartanburg County with documented family buyer preference — a market-supported Positive that partially offsets locational negatives for family buyers."}, "D": {"present": true, "classification": "Positive", "rationale": "Regional connectivity to Spartanburg and I-85 via SC-9 within 0.4 miles — a Positive supporting overall marketability."}, "E": {"present": true, "classification": "Positive", "rationale": "Zone X confirmed for the entire lot — no flood insurance requirement under FHA/HUD guidelines."}, "F": {"present": false}, "G": {"present": false}, "H": {"present": false}}}'::jsonb
FROM scenarios s
JOIN scenario_categories sc ON sc.id = s.category_id
JOIN module_sections ms ON ms.id = sc.section_id
JOIN section_fields f ON f.section_id = ms.id AND f.field_key = 'factor_analysis'
WHERE sc.code = 'M2-S5-C5'
  AND s.order_index = 4;

