INSERT INTO model_answers
  (scenario_id, field_id, answer_text, field_options_override, model_data)
SELECT
  s.id,
  f.id,
  '',
  '{"subject": {"address_summary": "3318 Highway 14, Greer, SC 29651", "subject_summary": "3BR/2BA · 1,620 SF · 2003-built SFR · Rural Greenville County · 0.55 acres", "context_label": "Government Context", "context_text": "SCDOT partial taking condemnation appraisal. Highway 14 widening project. The appraiser has been retained to establish the before-condition value of the subject property as of the date of value established by SCDOT. A partial strip of the front lot will be acquired for right-of-way. The before-condition analysis must reflect conditions as they existed at the date of value — not post-construction conditions."}, "location_profile": ["The subject is a single-family residence on a 0.55-acre lot on Highway 14 in rural Greenville County, approximately 7 miles east of downtown Greer. Highway 14 is a two-lane state highway at this location. As of the date of value, the subject has a 35-foot setback from the highway right-of-way and fronts directly on Highway 14, which carries moderate two-lane through-traffic. The SCDOT widening project will reduce the front setback to approximately 18 feet upon completion — that post-construction condition is not part of the before-condition analysis.", "As of the date of value, a light industrial equipment storage yard operates on the adjacent parcel to the north — documented in county records and aerial photography at the date of value. The Greer/Eastside school attendance zone applies — above-average in Greenville County. FEMA Zone X is confirmed. I-85 is accessible via SC-101 approximately 4 miles east — a positive regional connectivity attribute at the date of value. No airport noise contours or environmental hazards are identified at the date of value."], "factors": [{"id": "A", "label": "Highway 14 frontage (35-ft setback — before-condition at date of value)"}, {"id": "B", "label": "Industrial equipment storage yard (adjacent north parcel — date of value condition)"}, {"id": "C", "label": "Greer/Eastside school district (above average)"}, {"id": "D", "label": "I-85 regional connectivity (~4 miles, SC-101)"}, {"id": "E", "label": "FEMA Zone X"}, {"id": "F", "label": "Rural residential character (0.55-acre lot, low density)"}, {"id": "G", "label": "Reduced setback post-construction (18 ft — post-taking condition, not applicable)"}, {"id": "H", "label": "Four-lane divided highway (post-construction — not applicable at date of value)"}], "classification_options": ["Positive", "Negative", "Neutral", "Market-Dependent"], "min_rationale_chars": 20, "teaching_points": ["Teaching Point 1 — Before-condition analysis excludes all post-taking changes. Factors G and H represent post-construction conditions that do not exist at the date of value. The 18-foot post-construction setback and the four-lane divided highway are what the SCDOT project will create — they are the basis for the after-condition analysis, not the before-condition. Students who check G or H are applying post-taking knowledge to a before-condition assignment, which would inflate the apparent impact of the taking.", "Teaching Point 2 — Condemnation before-condition analysis is retrospective by nature. Like estate appraisal, condemnation before-condition analysis requires the appraiser to establish a clean snapshot of conditions at a specific date. The discipline is identical: every identified factor must be supported by evidence that existed at or before the date of value. SCDOT project records, historical aerial photography, and county permit data are primary sources for documenting the before-condition.", "Teaching Point 3 — All pre-existing negatives must be identified in the before-condition. Factors A and B are both pre-existing negatives that must appear in the before-condition analysis. If the appraiser omits pre-existing negatives, the before-condition value is overstated — which inflates the apparent impact of the taking and overstates the just compensation. Completeness of the before-condition locational profile is a fundamental obligation in condemnation appraisal."]}'::jsonb,
  '{"factors": {"A": {"present": true, "classification": "Negative", "rationale": "Direct frontage on a state two-lane highway at a 35-foot setback was the before-condition at the date of value — a Negative residential amenity factor that must be analyzed as it existed before the taking, not as it will exist after."}, "B": {"present": true, "classification": "Negative", "rationale": "An active light industrial storage operation immediately adjacent to the north was documented at the date of value — a proximity externality that is a Negative in the before-condition analysis."}, "C": {"present": true, "classification": "Positive", "rationale": "Above-average district with documented positive buyer reception — a market-supported Positive in the before-condition analysis."}, "D": {"present": true, "classification": "Positive", "rationale": "Regional access within 4 miles via SC-101 was a before-condition positive — providing employment and commercial connectivity at the date of value."}, "E": {"present": true, "classification": "Positive", "rationale": "Zone X confirmed at the date of value — no flood insurance requirement."}, "F": {"present": true, "classification": "Market-Dependent", "rationale": "Rural lot size and low density produces split buyer response — some buyers value the space and privacy; others prefer closer-in suburban locations. Market-Dependent is appropriate in a rural highway corridor context."}, "G": {"present": false}, "H": {"present": false}}}'::jsonb
FROM scenarios s
JOIN scenario_categories sc ON sc.id = s.category_id
JOIN module_sections ms ON ms.id = sc.section_id
JOIN section_fields f ON f.section_id = ms.id AND f.field_key = 'factor_analysis'
WHERE sc.code = 'M2-S5-C5'
  AND s.order_index = 5;

