-- Scenario 6: 2218 Runway View Lane, Greer — VA Purchase, GSP DNL 65 dB Contour
-- Category M2-S5-C5 #6 · difficulty 'intermediate'
-- ─────────────────────────────────────────────────────
INSERT INTO scenarios
  (category_id, order_index, difficulty, title, scenario_text)
SELECT id, 6,
  'intermediate',
  '2218 Runway View Lane, Greer — VA Purchase, GSP DNL 65 dB Contour',
  'You are performing a government locational analysis at 2218 Runway View Lane, Greer, SC 29651. The subject is 3BR/2BA · 1,800 SF · 2007-built SFR · Runway Commons. VA purchase appraisal. Veteran borrower. Lender: PenFed Credit Union. The subject falls within the FAA Part 150 Airport Noise Compatibility Study noise contour for Greenville-Spartanburg International Airport (GSP) at a Day-Night Average Sound Level (DNL) of 65 dB. Under VA Lender''s Handbook guidelines, a DNL of 65 dB or higher requires specific appraiser notation and underwriter review. The appraiser must address both market impact and VA guideline compliance. Section 5 — Locational Influence — requires you to identify which locational factors are present at the subject, classify each as Positive, Negative, Neutral, or Market-Dependent based on the location profile evidence, and write a brief market-supported rationale for each classification. Government appraisals require dual-lens analysis: each factor must be evaluated for both market value impact and program-specific compliance implications (VA MPRs, HUD Handbook 4000.1, condemnation before-condition, etc.). Distractor factors that are not present must be left unchecked, and each rationale must cite specific evidence from the location profile and address any compliance implications relevant to this assignment type.'
FROM scenario_categories WHERE code = 'M2-S5-C5';

INSERT INTO model_answers
  (scenario_id, field_id, answer_text, field_options_override, model_data)
SELECT
  s.id,
  f.id,
  '',
  '{"subject": {"address_summary": "2218 Runway View Lane, Greer, SC 29651", "subject_summary": "3BR/2BA · 1,800 SF · 2007-built SFR · Runway Commons", "context_label": "Government Context", "context_text": "VA purchase appraisal. Veteran borrower. Lender: PenFed Credit Union. The subject falls within the FAA Part 150 Airport Noise Compatibility Study noise contour for Greenville-Spartanburg International Airport (GSP) at a Day-Night Average Sound Level (DNL) of 65 dB. Under VA Lender''s Handbook guidelines, a DNL of 65 dB or higher requires specific appraiser notation and underwriter review. The appraiser must address both market impact and VA guideline compliance."}, "location_profile": ["The subject is located in a small residential subdivision approximately 2.2 miles from GSP''s primary runway. The FAA Part 150 study places the subject lot within the 65 dB DNL noise contour — the federal threshold for marginal residential compatibility. VA guidelines require the appraiser to note this designation and assess whether the noise impact affects the property''s marketability to the general public.", "2218 Runway View Lane is a cul-de-sac lot of 0.24 acres. Aircraft approach and departure noise is periodically audible at the subject location, consistent with the 65 dB DNL designation. BMW Manufacturing is approximately 3.5 miles southwest — a documented employment and demand driver in the Greer submarket. The school zone is average-performing in Greenville County with no documented premium. FEMA Zone X is confirmed for the entire lot. The surrounding land use is primarily residential with some light commercial along the access roads. No UST registrations or additional environmental hazards are identified."], "factors": [{"id": "A", "label": "FAA Part 150 noise contour (DNL 65 dB — VA notation required)"}, {"id": "B", "label": "Airport noise disclosure obligation (triggered by DNL 65 dB designation)"}, {"id": "C", "label": "Cul-de-sac location"}, {"id": "D", "label": "BMW Manufacturing proximity (~3.5 miles)"}, {"id": "E", "label": "Average school district (no documented premium)"}, {"id": "F", "label": "FEMA Zone X"}, {"id": "G", "label": "FEMA Zone AE"}, {"id": "H", "label": "Underground storage tank proximity"}], "classification_options": ["Positive", "Negative", "Neutral", "Market-Dependent"], "min_rationale_chars": 20, "teaching_points": ["Teaching Point 1 — DNL 65 dB is a VA guideline threshold, not just a market factor. Factor A triggers a specific VA procedural requirement: the appraiser must note the designation and assess general marketability. This is a dual obligation — the market classification (Negative) and the VA compliance notation are both required. Students who classify Factor A correctly as Negative but fail to recognize the VA notation requirement are completing only half of the government appraisal obligation.", "Teaching Point 2 — Noise and disclosure are analytically distinct factors. Factor B (disclosure obligation) is a consequence of Factor A (noise contour) but addresses a different dimension of the impact. The physical noise affects livability; the disclosure requirement affects transaction dynamics. Both must be identified independently because they affect different aspects of the VA marketability analysis. This mirrors the distinction taught in Module 1 Scenario 10.", "Teaching Point 3 — Positive factors still matter in a constrained government appraisal. Factors C, D, and F are genuine positives that must be identified even though the noise contour creates significant compliance concerns. Government appraisers who identify only the compliance risk factors and omit the positives are producing incomplete analyses. The complete locational profile — positive and negative — is what supports a defensible VA value conclusion."]}'::jsonb,
  '{"factors": {"A": {"present": true, "classification": "Negative", "rationale": "DNL 65 dB is the VA guideline threshold requiring appraiser notation and underwriter review. Audible aircraft noise at this level is a Negative affecting both residential marketability and VA appraisal compliance."}, "B": {"present": true, "classification": "Negative", "rationale": "The disclosure obligation triggered by the noise contour designation is analytically distinct from the noise itself — it introduces transaction-level friction and may deter buyers upon disclosure, compounding the noise impact."}, "C": {"present": true, "classification": "Positive", "rationale": "Cul-de-sac terminus with minimal through-traffic — a consistently positive market configuration with no VA MPR concerns."}, "D": {"present": true, "classification": "Positive", "rationale": "BMW employment proximity is a documented demand driver in the Greer submarket — a Positive supporting overall VA appraisal marketability."}, "E": {"present": true, "classification": "Neutral", "rationale": "Average-performing zone with no documented buyer premium or discount — Neutral in both market and VA marketability analysis."}, "F": {"present": true, "classification": "Positive", "rationale": "Zone X confirmed — no flood insurance requirement under VA lending guidelines."}, "G": {"present": false}, "H": {"present": false}}}'::jsonb
FROM scenarios s
JOIN scenario_categories sc ON sc.id = s.category_id
JOIN module_sections ms ON ms.id = sc.section_id
JOIN section_fields f ON f.section_id = ms.id AND f.field_key = 'factor_analysis'
WHERE sc.code = 'M2-S5-C5'
  AND s.order_index = 6;

