-- Scenario 7: 847 Industrial Creek Road, Spartanburg — FHA Purchase, Triple Compliance Concerns
-- Category M2-S5-C5 #7 · difficulty 'advanced'
-- ─────────────────────────────────────────────────────
INSERT INTO scenarios
  (category_id, order_index, difficulty, title, scenario_text)
SELECT id, 7,
  'advanced',
  '847 Industrial Creek Road, Spartanburg — FHA Purchase, Triple Compliance Concerns',
  'You are performing a government locational analysis at 847 Industrial Creek Road, Spartanburg, SC 29301. The subject is 3BR/2BA · 1,540 SF · 1994-built SFR · Industrial Creek Area. FHA purchase appraisal. Lender: Palmetto Citizens Federal Credit Union. HUD Handbook 4000.1 applies. Multiple potential FHA compliance issues have been flagged by the lender prior to assignment: (1) Zone AE designation on a rear lot portion; (2) proximity to a former industrial site listed on the SCDHEC Brownfield registry approximately 0.3 miles north; and (3) a 100kV overhead transmission line crossing the rear lot area. The appraiser must address all three flagged conditions and all additional locational factors. Section 5 — Locational Influence — requires you to identify which locational factors are present at the subject, classify each as Positive, Negative, Neutral, or Market-Dependent based on the location profile evidence, and write a brief market-supported rationale for each classification. Government appraisals require dual-lens analysis: each factor must be evaluated for both market value impact and program-specific compliance implications (VA MPRs, HUD Handbook 4000.1, condemnation before-condition, etc.). Distractor factors that are not present must be left unchecked, and each rationale must cite specific evidence from the location profile and address any compliance implications relevant to this assignment type.'
FROM scenario_categories WHERE code = 'M2-S5-C5';

INSERT INTO model_answers
  (scenario_id, field_id, answer_text, field_options_override, model_data)
SELECT
  s.id,
  f.id,
  '',
  '{"subject": {"address_summary": "847 Industrial Creek Road, Spartanburg, SC 29301", "subject_summary": "3BR/2BA · 1,540 SF · 1994-built SFR · Industrial Creek Area", "context_label": "Government Context", "context_text": "FHA purchase appraisal. Lender: Palmetto Citizens Federal Credit Union. HUD Handbook 4000.1 applies. Multiple potential FHA compliance issues have been flagged by the lender prior to assignment: (1) Zone AE designation on a rear lot portion; (2) proximity to a former industrial site listed on the SCDHEC Brownfield registry approximately 0.3 miles north; and (3) a 100kV overhead transmission line crossing the rear lot area. The appraiser must address all three flagged conditions and all additional locational factors."}, "location_profile": ["The subject is a single-family residence in a mixed residential-industrial area of western Spartanburg, approximately 3 miles from downtown. The immediate area includes older residential properties, a light industrial zone to the north, and commercial uses along the primary corridor. Spartanburg Regional Medical Center is approximately 2.5 miles east — a secondary employment driver.", "847 Industrial Creek Road is a through-street lot of 0.28 acres. The rear portion of the lot falls within FEMA Zone AE; the structure is in Zone X. A 100kV Duke Energy overhead transmission line crosses the rear portion of the lot — not directly over the structure but within the lot boundaries. A former industrial site listed on the SCDHEC Brownfield registry is approximately 0.3 miles north; no active remediation is ongoing but the listing status is current. The school zone is below-average for Spartanburg County. I-26 access is approximately 2 miles east."], "factors": [{"id": "A", "label": "FEMA Zone AE (rear lot portion — FHA flood insurance required)"}, {"id": "B", "label": "SCDHEC Brownfield registry site (~0.3 miles north)"}, {"id": "C", "label": "100kV overhead transmission line crossing rear lot area"}, {"id": "D", "label": "Mixed residential-industrial area character"}, {"id": "E", "label": "Below-average school district"}, {"id": "F", "label": "Spartanburg Regional Medical Center proximity (~2.5 miles)"}, {"id": "G", "label": "I-26 regional access (~2 miles)"}, {"id": "H", "label": "FEMA Zone X (structure location)"}, {"id": "I", "label": "HOA amenity or greenspace"}, {"id": "J", "label": "Airport noise contour"}], "classification_options": ["Positive", "Negative", "Neutral", "Market-Dependent"], "min_rationale_chars": 20, "teaching_points": ["Teaching Point 1 — Multiple simultaneous FHA compliance issues require independent analysis. Factors A, B, and C each trigger separate HUD Handbook 4000.1 provisions and each must be addressed independently in the FHA appraisal report. A student who groups them into a single compliance notation has produced a report that fails to address each condition with the specificity HUD requires. FHA underwriters review each flagged condition separately.", "Teaching Point 2 — Brownfield listing is not the same as active contamination. Factor B is Negative because the Brownfield listing is current — not because active contamination is confirmed. HUD requires appraiser notation for any known environmental site in the immediate area regardless of remediation status. Students who classify Factor B as Neutral because no active contamination is documented are applying a market standard rather than a government lending standard.", "Teaching Point 3 — Positive factors do not offset compliance issues. Factors F, G, and H are genuine positives that must be identified. But in an FHA analysis, positive locational factors do not mitigate or offset MPR compliance concerns — the compliance issues must be resolved on their own terms regardless of how many positives exist. Students who reason that the positives reduce the severity of the compliance negatives are conflating market reconciliation with regulatory compliance."]}'::jsonb,
  '{"factors": {"A": {"present": true, "classification": "Negative", "rationale": "Zone AE on any lot portion triggers mandatory FHA flood insurance regardless of structure location in Zone X. A Negative with direct FHA eligibility consequences — same rule as VA, applied under HUD Handbook 4000.1."}, "B": {"present": true, "classification": "Negative", "rationale": "An active Brownfield listing within 0.3 miles requires FHA appraiser notation under HUD Handbook 4000.1 environmental hazard provisions. A Negative affecting both FHA eligibility review and general market buyer pool depth."}, "C": {"present": true, "classification": "Negative", "rationale": "An overhead high-voltage transmission line crossing within the lot boundaries requires FHA appraiser notation. VA and FHA guidelines flag transmission lines crossing over or within close proximity to the property as a condition requiring underwriter review."}, "D": {"present": true, "classification": "Negative", "rationale": "The mixed residential-industrial land use context constrains the residential buyer pool and is a Negative for overall FHA marketability — buyers must be willing to accept the industrial corridor environment."}, "E": {"present": true, "classification": "Negative", "rationale": "Below-average school zone is a market Negative constraining the buyer pool — compounding the marketability concerns already present from Factors A through D."}, "F": {"present": true, "classification": "Positive", "rationale": "Healthcare employment proximity at 2.5 miles provides a secondary demand driver — a Positive supporting demand despite significant locational negatives."}, "G": {"present": true, "classification": "Positive", "rationale": "I-26 access within 2 miles provides regional employment connectivity — a Positive supporting marketability in a constrained locational profile."}, "H": {"present": true, "classification": "Positive", "rationale": "Zone X for the structure is a partial positive but does not override Zone AE on the rear lot for FHA flood insurance purposes."}, "I": {"present": false}, "J": {"present": false}}}'::jsonb
FROM scenarios s
JOIN scenario_categories sc ON sc.id = s.category_id
JOIN module_sections ms ON ms.id = sc.section_id
JOIN section_fields f ON f.section_id = ms.id AND f.field_key = 'factor_analysis'
WHERE sc.code = 'M2-S5-C5'
  AND s.order_index = 7;

