INSERT INTO scenarios
  (category_id, order_index, difficulty, title, scenario_text)
SELECT id, 8,
  'advanced',
  '1847 Old Highway 29, Greer — SCDOT Interchange Project Before-Condition',
  'You are performing a government locational analysis at 1847 Old Highway 29, Greer, SC 29651. The subject is 3BR/2BA · 1,680 SF · 1999-built SFR · Rural Greenville County · 0.48 acres. SCDOT partial taking condemnation appraisal. I-85 interchange improvement project at the Highway 29/SC-101 junction. The SCDOT project will acquire a partial strip of the subject''s front lot for expanded right-of-way and will construct a new on/off ramp structure approximately 180 feet from the subject''s front door upon completion. The before-condition analysis must establish the locational profile as it existed at the date of value — before the interchange construction began. Section 5 — Locational Influence — requires you to identify which locational factors are present at the subject, classify each as Positive, Negative, Neutral, or Market-Dependent based on the location profile evidence, and write a brief market-supported rationale for each classification. Government appraisals require dual-lens analysis: each factor must be evaluated for both market value impact and program-specific compliance implications (VA MPRs, HUD Handbook 4000.1, condemnation before-condition, etc.). Distractor factors that are not present must be left unchecked, and each rationale must cite specific evidence from the location profile and address any compliance implications relevant to this assignment type.'
