INSERT INTO model_answers
  (scenario_id, field_id, answer_text, field_options_override, model_data)
SELECT
  s.id,
  f.id,
  '',
  '{"subject": {"address_summary": "1847 Old Highway 29, Greer, SC 29651", "subject_summary": "3BR/2BA · 1,680 SF · 1999-built SFR · Rural Greenville County · 0.48 acres", "context_label": "Government Context", "context_text": "SCDOT partial taking condemnation appraisal. I-85 interchange improvement project at the Highway 29/SC-101 junction. The SCDOT project will acquire a partial strip of the subject''s front lot for expanded right-of-way and will construct a new on/off ramp structure approximately 180 feet from the subject''s front door upon completion. The before-condition analysis must establish the locational profile as it existed at the date of value — before the interchange construction began."}, "location_profile": ["The subject is a single-family residence on a 0.48-acre lot on Old Highway 29 in Greer, approximately 1.8 miles from the existing I-85/SC-101 interchange. As of the date of value, the existing interchange is a full cloverleaf with standard on/off ramps at grade — no construction activity had commenced. Old Highway 29 carries moderate two-lane through-traffic at the date of value, with commercial truck activity associated with the nearby BMW logistics corridor.", "As of the date of value, the subject has a 42-foot setback from the Old Highway 29 right-of-way. The BMW Manufacturing campus is approximately 2.5 miles southwest — a documented employment and demand driver at the date of value. The school zone is above-average in Greenville County with positive documented buyer reception. FEMA Zone X is confirmed at the date of value. A small auto repair shop operates approximately 0.4 miles east on Highway 29 — a minor commercial use with no direct audible or visual impact on the subject at the date of value."], "factors": [{"id": "A", "label": "Old Highway 29 through-traffic / commercial truck activity (42-ft setback — date of value)"}, {"id": "B", "label": "I-85 / SC-101 interchange proximity — existing cloverleaf (date of value)"}, {"id": "C", "label": "BMW Manufacturing proximity (~2.5 miles — date of value)"}, {"id": "D", "label": "Above-average school district (date of value)"}, {"id": "E", "label": "FEMA Zone X"}, {"id": "F", "label": "Auto repair shop (~0.4 miles east — minor, no direct impact at date of value)"}, {"id": "G", "label": "Expanded right-of-way strip acquisition (post-taking — not applicable at date of value)"}, {"id": "H", "label": "New on/off ramp structure 180 ft from subject (post-construction — not applicable)"}, {"id": "I", "label": "Increased traffic from completed interchange (post-construction — not applicable)"}], "classification_options": ["Positive", "Negative", "Neutral", "Market-Dependent"], "min_rationale_chars": 20, "teaching_points": ["Teaching Point 1 — Three post-construction distractors test before-condition discipline. Factors G, H, and I all represent post-construction conditions that do not exist at the date of value. Each represents a consequence of the SCDOT project that will worsen the residential conditions — reduced lot area, a new ramp structure at close proximity, and increased traffic. Students who check any of these factors are analyzing the after-condition, not the before-condition, and would produce an inflated damage estimate.", "Teaching Point 2 — Existing connectivity is a before-condition positive, not a neutral. Factor B (existing interchange) is a Positive at the date of value because the current cloverleaf provides the regional connectivity that makes the BMW corridor accessible. Students who classify this as Neutral — perhaps because it seems to be a background condition — are missing a positive that exists at the date of value and contributes to before-condition value.", "Teaching Point 3 — Condemnation before-condition completeness is a legal obligation. In South Carolina condemnation proceedings, the before-condition value must be established by a licensed appraiser using USPAP-compliant methodology. An incomplete before-condition locational analysis is not merely a technical deficiency — it is a legal vulnerability. Counsel for the property owner and SCDOT will both scrutinize the locational analysis for omissions that could affect the just compensation determination."]}'::jsonb,
  '{"factors": {"A": {"present": true, "classification": "Negative", "rationale": "Moderate through-traffic with commercial truck activity on a two-lane highway at a 42-foot setback was a Negative before-condition at the date of value — existing prior to the I-85 project commencement."}, "B": {"present": true, "classification": "Positive", "rationale": "A full I-85 interchange within 1.8 miles was a Positive regional connectivity attribute at the date of value — providing employment and commercial access to the BMW corridor and broader Upstate market."}, "C": {"present": true, "classification": "Positive", "rationale": "BMW proximity was a documented employment demand driver at the date of value — a Positive supporting residential marketability in the Greer submarket."}, "D": {"present": true, "classification": "Positive", "rationale": "Above-average district with documented positive buyer reception — same zone at the date of value as today."}, "E": {"present": true, "classification": "Positive", "rationale": "Zone X confirmed at the date of value — no flood insurance requirement."}, "F": {"present": true, "classification": "Neutral", "rationale": "A small auto repair operation 0.4 miles away with no audible or visible impact on the subject at the date of value — Neutral classification is appropriate at this distance and intensity."}, "G": {"present": false}, "H": {"present": false}, "I": {"present": false}}}'::jsonb
FROM scenarios s
JOIN scenario_categories sc ON sc.id = s.category_id
JOIN module_sections ms ON ms.id = sc.section_id
JOIN section_fields f ON f.section_id = ms.id AND f.field_key = 'factor_analysis'
WHERE sc.code = 'M2-S5-C5'
  AND s.order_index = 8;

