  '',
  '{"subject": {"address_summary": "412 Reedy Fork Road, Greenville, SC 29607", "subject_summary": "3BR/2BA · 1,760 SF · 2004-built SFR · Reedy Fork Corridor", "context_label": "Government Context", "context_text": "VA purchase appraisal. Veteran borrower. Lender: Navy Federal Credit Union. Pre-appraisal review by the lender''s VA compliance officer has identified three potential MPR concerns at this address: (1) the lot falls within the 65 dB DNL noise contour for GSP''s instrument approach path; (2) a SCDHEC-registered dry cleaning solvent site (PCE) is documented approximately 0.25 miles north; and (3) a partial Zone AE designation on the rear lot is indicated on the current FEMA FIRM panel. The appraiser must address all three conditions and all additional locational factors."}, "location_profile": ["The subject is located in a residential area of eastern Greenville County, approximately 6 miles from GSP. The FAA Part 150 study places the subject within the instrument approach path noise contour at DNL 65 dB. Aircraft approach noise is intermittently audible at the property during instrument operations, consistent with the designation. A dry cleaning operation that used PCE (perchloroethylene) solvents ceased operations approximately 8 years ago; the site is registered with SCDHEC and monitored but no active remediation is currently underway.", "412 Reedy Fork Road is a through-street lot of 0.26 acres. FEMA map review confirms Zone AE begins approximately 30 feet behind the rear building line; the structure is in Zone X. The subject is in the above-average Eastside/Blue Ridge school attendance zone with documented positive buyer reception. I-385 is accessible approximately 1.5 miles south — strong regional connectivity. GHS Patewood Medical Campus is approximately 3 miles west. FEMA Zone X covers the structure; Zone AE covers the rear lot area."], "factors": [{"id": "A", "label": "FAA Part 150 noise contour (DNL 65 dB — VA notation required)"}, {"id": "B", "label": "PCE dry cleaning solvent site (SCDHEC registered, ~0.25 miles, monitored)"}, {"id": "C", "label": "FEMA Zone AE (rear lot — VA flood insurance required)"}, {"id": "D", "label": "Through-street location (moderate residential traffic)"}, {"id": "E", "label": "Above-average school district (Eastside/Blue Ridge)"}, {"id": "F", "label": "I-385 regional connectivity (~1.5 miles)"}, {"id": "G", "label": "GHS Patewood Medical Campus proximity (~3 miles)"}, {"id": "H", "label": "FEMA Zone X (structure location)"}, {"id": "I", "label": "HOA restrictions or amenity"}, {"id": "J", "label": "Industrial manufacturing nuisance adjacency"}], "classification_options": ["Positive", "Negative", "Neutral", "Market-Dependent"], "min_rationale_chars": 20, "teaching_points": ["Teaching Point 1 — Three simultaneous VA compliance concerns require independent notation. Factors A, B, and C each trigger separate VA Lender''s Handbook provisions and must be addressed independently. A VA appraisal with three simultaneous compliance concerns will receive heightened underwriter scrutiny — the appraiser''s job is to be complete, precise, and factual about each condition without overstating or understating any of them.", "Teaching Point 2 — Monitored but unresolved environmental site is still a compliance concern. Factor B is Negative because the SCDHEC registry listing is current, even though active remediation is not underway. The distinction matters: active remediation indicates ongoing risk management; monitoring without remediation indicates an unresolved condition. VA appraisers must represent the current status accurately — neither dismissing a registered site as resolved nor characterizing it as more severe than the registry documentation supports.", "Teaching Point 3 — Positive factors in a high-compliance-concern scenario are still required. Factors E, F, G, and H are genuine positives that must be identified even though three VA compliance negatives dominate the analysis. The complete locational picture matters because: (1) USPAP requires completeness; (2) the VA underwriter needs the full context to make an eligibility determination; and (3) the positive factors establish the market value baseline that the compliance concerns are measured against."]}'::jsonb,
  '{"factors": {"A": {"present": true, "classification": "Negative", "rationale": "DNL 65 dB on the GSP instrument approach path triggers VA appraiser notation and underwriter review. Intermittent audible aircraft noise compounds the regulatory designation with a measurable residential amenity negative."}, "B": {"present": true, "classification": "Negative", "rationale": "An active SCDHEC environmental registry listing within 0.25 miles requires VA appraiser notation under environmental hazard provisions. A monitored but unresolved solvent site at this proximity is a Negative for both VA eligibility review and general buyer pool depth."}, "C": {"present": true, "classification": "Negative", "rationale": "Zone AE on any lot portion triggers mandatory flood insurance under VA MPRs. Three simultaneous VA compliance negatives (A, B, C) place this property in a high-scrutiny underwriting category."}, "D": {"present": true, "classification": "Negative", "rationale": "Through-street with moderate traffic is a modest market Negative — less significant than the three VA compliance negatives but still a present factor that must be identified."}, "E": {"present": true, "classification": "Positive", "rationale": "Above-average district with documented positive buyer reception — a market-supported Positive supporting overall VA marketability despite compliance concerns."}, "F": {"present": true, "classification": "Positive", "rationale": "I-385 access within 1.5 miles is strong regional connectivity — a Positive supporting employment and commercial access."}, "G": {"present": true, "classification": "Positive", "rationale": "Medical employment proximity at 3 miles contributes to healthcare worker demand — a Positive supporting overall VA appraisal marketability."}, "H": {"present": true, "classification": "Positive", "rationale": "Zone X for the structure is a partial positive — though it does not override Zone AE on the rear lot for VA flood insurance purposes."}, "I": {"present": false}, "J": {"present": false}}}'::jsonb
FROM scenarios s
JOIN scenario_categories sc ON sc.id = s.category_id
JOIN module_sections ms ON ms.id = sc.section_id
JOIN section_fields f ON f.section_id = ms.id AND f.field_key = 'factor_analysis'
WHERE sc.code = 'M2-S5-C5'
  AND s.order_index = 9;

