-- Scenario 10: 3318 Old Buncombe Road, Greenville — FHA Refinance, Historic Overlay + Brownfield + Zone AE
-- Category M2-S5-C5 #10 · difficulty 'expert'
-- ─────────────────────────────────────────────────────
INSERT INTO scenarios
  (category_id, order_index, difficulty, title, scenario_text)
SELECT id, 10,
  'expert',
  '3318 Old Buncombe Road, Greenville — FHA Refinance, Historic Overlay + Brownfield + Zone AE',
  'You are performing a government locational analysis at 3318 Old Buncombe Road, Greenville, SC 29609. The subject is 4BR/2BA · 2,100 SF · 1962-built SFR (updated 2017) · Old Buncombe Corridor. FHA appraisal for refinance under FHA Streamline with appraisal requirement. Lender: Movement Mortgage. HUD Handbook 4000.1 applies. The property is in a historic overlay district. HUD has specific requirements for properties in historic districts — the appraiser must identify whether the overlay imposes conditions that affect marketability or create compliance concerns under FHA guidelines. In addition to historic overlay, the lender has flagged proximity to a documented former industrial site and a partial Zone AE designation for review. Section 5 — Locational Influence — requires you to identify which locational factors are present at the subject, classify each as Positive, Negative, Neutral, or Market-Dependent based on the location profile evidence, and write a brief market-supported rationale for each classification. Government appraisals require dual-lens analysis: each factor must be evaluated for both market value impact and program-specific compliance implications (VA MPRs, HUD Handbook 4000.1, condemnation before-condition, etc.). Distractor factors that are not present must be left unchecked, and each rationale must cite specific evidence from the location profile and address any compliance implications relevant to this assignment type.'
FROM scenario_categories WHERE code = 'M2-S5-C5';

INSERT INTO model_answers
  (scenario_id, field_id, answer_text, field_options_override, model_data)
SELECT
  s.id,
  f.id,
  '',
  '{"subject": {"address_summary": "3318 Old Buncombe Road, Greenville, SC 29609", "subject_summary": "4BR/2BA · 2,100 SF · 1962-built SFR (updated 2017) · Old Buncombe Corridor", "context_label": "Government Context", "context_text": "FHA appraisal for refinance under FHA Streamline with appraisal requirement. Lender: Movement Mortgage. HUD Handbook 4000.1 applies. The property is in a historic overlay district. HUD has specific requirements for properties in historic districts — the appraiser must identify whether the overlay imposes conditions that affect marketability or create compliance concerns under FHA guidelines. In addition to historic overlay, the lender has flagged proximity to a documented former industrial site and a partial Zone AE designation for review."}, "location_profile": ["The subject is located in a residential area of northern Greenville along Old Buncombe Road, approximately 2.5 miles from downtown. The property falls within a City of Greenville historic overlay district governing exterior modifications and requiring design review board approval for visible alterations. HUD Handbook 4000.1 does not prohibit FHA financing for historic properties but requires that any deed restrictions or overlay requirements be reviewed for their effect on marketability and the borrower''s ability to maintain and repair the property.", "3318 Old Buncombe Road is a through-street lot of 0.20 acres with a 28-foot setback from Old Buncombe Road, which carries moderate arterial traffic. A former textile mill site listed on the SCDHEC Brownfield registry is approximately 0.28 miles north — currently subject to an active monitored natural attenuation remediation plan. The rear lot portion falls within FEMA Zone AE; the structure is in Zone X. The subject is in a below-average Greenville County school zone. Downtown Greenville is approximately 2.5 miles south. FEMA Zone X covers the structure."], "factors": [{"id": "A", "label": "Historic overlay district (design review requirements — HUD marketability review required)"}, {"id": "B", "label": "SCDHEC Brownfield registry site — active monitored natural attenuation (~0.28 miles)"}, {"id": "C", "label": "FEMA Zone AE (rear lot — FHA flood insurance required)"}, {"id": "D", "label": "Old Buncombe Road moderate arterial traffic (28-ft setback)"}, {"id": "E", "label": "Below-average school district"}, {"id": "F", "label": "Downtown Greenville proximity (~2.5 miles)"}, {"id": "G", "label": "FEMA Zone X (structure location)"}, {"id": "H", "label": "Established residential neighborhood character"}, {"id": "I", "label": "HOA use restrictions"}, {"id": "J", "label": "Airport noise contour"}, {"id": "K", "label": "Railroad proximity"}], "classification_options": ["Positive", "Negative", "Neutral", "Market-Dependent"], "min_rationale_chars": 20, "teaching_points": ["Teaching Point 1 — Historic overlay is Market-Dependent under FHA, not automatically Negative. HUD Handbook 4000.1 requires the appraiser to assess whether the historic overlay materially impairs marketability — it does not treat the overlay as a disqualifying condition. Market-Dependent is the analytically correct classification because buyer response is genuinely split and the HUD assessment requires evidence-based analysis, not assumption. Students who classify the historic overlay as Negative by default are applying a standard more restrictive than HUD requires.", "Teaching Point 2 — Active remediation is more significant than passive monitoring. Factor B involves an active monitored natural attenuation plan — meaning the contamination is acknowledged, a remediation pathway is in place, but the site has not been cleared. This is more significant than a legacy listing with no current activity. FHA appraisers must understand the distinction between active remediation, passive monitoring, and closed/cleared status — and represent the current status accurately in the appraisal report.", "Teaching Point 3 — Multiple simultaneous compliance issues in a government refinance require systematic analysis. This scenario has four compliance-related factors (A, B, C, D) alongside four market factors (E–H). In an FHA refinance with multiple flagged compliance concerns, the appraiser must address each independently and explicitly in the report — the underwriter cannot resolve unstated concerns. Students who produce a narrative that mentions the compliance issues generally but does not classify and address each one separately are producing a report that will fail FHA review."]}'::jsonb,
  '{"factors": {"A": {"present": true, "classification": "Market-Dependent", "rationale": "The historic overlay imposes exterior modification restrictions that produce split buyer response — some value character preservation; others find the approval process burdensome. Market-Dependent is appropriate; HUD requires the appraiser to assess whether the overlay materially impairs marketability, not to assume it does or does not."}, "B": {"present": true, "classification": "Negative", "rationale": "An active Brownfield registry listing with ongoing monitored remediation within 0.28 miles requires FHA appraiser notation. Active remediation status is more significant than passive monitoring — a Negative with direct HUD Handbook compliance implications."}, "C": {"present": true, "classification": "Negative", "rationale": "Zone AE on any lot portion triggers mandatory FHA flood insurance under HUD Handbook 4000.1 — same rule as VA, applied to this FHA refinance assignment."}, "D": {"present": true, "classification": "Negative", "rationale": "Moderate arterial traffic at a 28-foot setback introduces noise and commercial character concerns — a market Negative compounding the compliance-driven negatives."}, "E": {"present": true, "classification": "Negative", "rationale": "Below-average school zone is a market Negative constraining the general buyer pool — relevant to FHA marketability analysis."}, "F": {"present": true, "classification": "Positive", "rationale": "Downtown Greenville access within 2.5 miles provides employment, retail, and amenity connectivity — a Positive supporting overall FHA marketability in this corridor."}, "G": {"present": true, "classification": "Positive", "rationale": "Zone X for the structure is a partial positive — it does not override Zone AE on the rear lot for FHA flood insurance purposes but is a genuine condition that must be identified."}, "H": {"present": true, "classification": "Positive", "rationale": "Owner-occupied with mature landscaping and an established residential character — a Positive relative to transitional or developing areas."}, "I": {"present": false}, "J": {"present": false}, "K": {"present": false}}}'::jsonb
FROM scenarios s
JOIN scenario_categories sc ON sc.id = s.category_id
JOIN module_sections ms ON ms.id = sc.section_id
JOIN section_fields f ON f.section_id = ms.id AND f.field_key = 'factor_analysis'
WHERE sc.code = 'M2-S5-C5'
  AND s.order_index = 10;

