-- ─────────────────────────────────────────────────────
-- Scenario 1: 218 Lakefront Drive, Inman — Lake Bowen Direct Waterfront with Permitted Dock
-- Category M2-S5-C6 #1 · difficulty 'introductory'
-- ─────────────────────────────────────────────────────
INSERT INTO scenarios
  (category_id, order_index, difficulty, title, scenario_text)
SELECT id, 1,
  'introductory',
  '218 Lakefront Drive, Inman — Lake Bowen Direct Waterfront with Permitted Dock',
  'You are performing a specialty locational analysis at 218 Lakefront Drive, Inman, SC 29349. The subject is 3BR/2BA · 1,840 SF · 2008-built SFR · Lake Bowen Shores. Specialty appraisal — direct waterfront residential property on Lake Bowen, a Spartanburg CPW reservoir of approximately 1,200 acres in northern Spartanburg County. The specialty characteristic is direct lake frontage with a private permitted dock. The appraiser must identify and classify all locational factors and establish the waterfront tier position clearly. Section 5 — Locational Influence — requires you to identify which locational factors are present at the subject, classify each as Positive, Negative, Neutral, or Market-Dependent based on the location profile evidence and the specialty framework, and write a brief market-supported rationale for each classification. Specialty assignments require the appraiser to identify the relevant specialty characteristics first (waterfront tier, ADU, STR, mountain market, etc.) and then analyze every locational factor through the lens of those characteristics simultaneously. Distractor factors that are not present must be left unchecked, and each rationale must cite specific evidence and connect the factor to the relevant specialty framework.'
FROM scenario_categories WHERE code = 'M2-S5-C6';

INSERT INTO model_answers
  (scenario_id, field_id, answer_text, field_options_override, model_data)
SELECT
  s.id,
  f.id,
  '',
  '{"subject": {"address_summary": "218 Lakefront Drive, Inman, SC 29349", "subject_summary": "3BR/2BA · 1,840 SF · 2008-built SFR · Lake Bowen Shores", "context_label": "Specialty Context", "context_text": "Specialty appraisal — direct waterfront residential property on Lake Bowen, a Spartanburg CPW reservoir of approximately 1,200 acres in northern Spartanburg County. The specialty characteristic is direct lake frontage with a private permitted dock. The appraiser must identify and classify all locational factors and establish the waterfront tier position clearly."}, "location_profile": ["Lake Bowen Shores is a residential community of approximately 95 homes on the southern shore of Lake Bowen near Inman. Direct waterfront lots in the community are scarce relative to the broader market and command documented premiums. 218 Lakefront Drive has approximately 85 feet of direct lake frontage with a private permitted dock. The primary buyer pool is owner-occupants and second-home buyers seeking Lake Bowen recreational access.", "The subject is a cul-de-sac lot approximately 0.15 miles from the primary lake access road. The school zone is average for Spartanburg County with no documented premium. FEMA Zone AE covers the rear lot portion adjacent to the lake; the structure is in Zone X. BMW Manufacturing is approximately 18 miles southwest — not a primary demand driver for this lake market. No environmental hazards or highway noise contours affect the subject."], "factors": [{"id": "A", "label": "Direct Lake Bowen waterfront (85 ft frontage, private permitted dock)"}, {"id": "B", "label": "FEMA Zone AE (rear lot, lake adjacency — flood insurance required)"}, {"id": "C", "label": "Cul-de-sac location"}, {"id": "D", "label": "FEMA Zone X (structure location)"}, {"id": "E", "label": "Average school district (no documented premium)"}, {"id": "F", "label": "Deeded community water access (not direct frontage — distractor)"}, {"id": "G", "label": "Mountain or scenic view"}], "classification_options": ["Positive", "Negative", "Neutral", "Market-Dependent"], "min_rationale_chars": 20, "teaching_points": ["Teaching Point 1 — Direct waterfront and community access are distinct tiers. Factor A is direct frontage with a private dock — categorically different from deeded community access via an HOA boat ramp. These two conditions are different tiers with materially different value impacts. Factor F is a distractor precisely because students may conflate the tiers. You either have direct frontage or you have community access — they cannot both be present at the same property.", "Teaching Point 2 — Zone AE and waterfront are analytically independent. Factor B (Zone AE) and Factor A (direct waterfront) both result from the same physical lake adjacency but address different dimensions of the locational profile. The waterfront is a Positive; the Zone AE is a Negative. Both must be identified and classified independently. The waterfront premium does not cancel the Zone AE negative — buyers still pay mandatory flood insurance regardless of the view.", "Teaching Point 3 — Distractor F tests tier discipline from the outset. The community access distractor tests whether students apply waterfront tier knowledge from the very first specialty scenario. In lake market appraisal, the most consequential identification error is misrepresenting the tier. Every waterfront scenario requires the appraiser to document specifically which tier the subject occupies — direct frontage, community access, or no access."]}'::jsonb,
  '{"factors": {"A": {"present": true, "classification": "Positive", "rationale": "Direct frontage with a private dock is the defining specialty characteristic. Documented premiums for direct waterfront over community-access lots in this submarket establish the Positive classification."}, "B": {"present": true, "classification": "Negative", "rationale": "Zone AE on any portion of the lot triggers mandatory flood insurance. A Negative that coexists independently with the direct waterfront Positive — the premium does not offset the insurance cost or regulatory designation."}, "C": {"present": true, "classification": "Positive", "rationale": "Cul-de-sac terminus with minimal through-traffic — a consistently positive configuration with no specialty context complications."}, "D": {"present": true, "classification": "Positive", "rationale": "Zone X for the structure is a partial positive — it reduces flood risk to the structure itself, though it does not override the Zone AE designation for flood insurance purposes."}, "E": {"present": true, "classification": "Neutral", "rationale": "Average-performing zone with no documented buyer premium — Neutral in both primary residential and second-home market contexts."}, "F": {"present": false}, "G": {"present": false}}}'::jsonb
FROM scenarios s
JOIN scenario_categories sc ON sc.id = s.category_id
JOIN module_sections ms ON ms.id = sc.section_id
JOIN section_fields f ON f.section_id = ms.id AND f.field_key = 'factor_analysis'
WHERE sc.code = 'M2-S5-C6'
  AND s.order_index = 1;

