-- Scenario 2: 847 Lake View Road, Inman — Lake Bowen Deeded Community Access
-- Category M2-S5-C6 #2 · difficulty 'introductory'
-- ─────────────────────────────────────────────────────
INSERT INTO scenarios
  (category_id, order_index, difficulty, title, scenario_text)
SELECT id, 2,
  'introductory',
  '847 Lake View Road, Inman — Lake Bowen Deeded Community Access',
  'You are performing a specialty locational analysis at 847 Lake View Road, Inman, SC 29349. The subject is 3BR/2BA · 1,680 SF · 2004-built SFR · Lake Bowen Village. Specialty appraisal — residential property in a Lake Bowen area subdivision with deeded HOA community water access but no direct lake frontage. The specialty characteristic is the tier-2 lake access position: deeded community boat ramp and dock access for all subdivision residents. The appraiser must establish the tier position accurately and classify all present locational factors. Section 5 — Locational Influence — requires you to identify which locational factors are present at the subject, classify each as Positive, Negative, Neutral, or Market-Dependent based on the location profile evidence and the specialty framework, and write a brief market-supported rationale for each classification. Specialty assignments require the appraiser to identify the relevant specialty characteristics first (waterfront tier, ADU, STR, mountain market, etc.) and then analyze every locational factor through the lens of those characteristics simultaneously. Distractor factors that are not present must be left unchecked, and each rationale must cite specific evidence and connect the factor to the relevant specialty framework.'
FROM scenario_categories WHERE code = 'M2-S5-C6';

INSERT INTO model_answers
  (scenario_id, field_id, answer_text, field_options_override, model_data)
SELECT
  s.id,
  f.id,
  '',
  '{"subject": {"address_summary": "847 Lake View Road, Inman, SC 29349", "subject_summary": "3BR/2BA · 1,680 SF · 2004-built SFR · Lake Bowen Village", "context_label": "Specialty Context", "context_text": "Specialty appraisal — residential property in a Lake Bowen area subdivision with deeded HOA community water access but no direct lake frontage. The specialty characteristic is the tier-2 lake access position: deeded community boat ramp and dock access for all subdivision residents. The appraiser must establish the tier position accurately and classify all present locational factors."}, "location_profile": ["Lake Bowen Village is a residential subdivision of approximately 140 homes approximately 0.4 miles from Lake Bowen. The subdivision was developed with a deeded HOA community boat ramp and dock on Lake Bowen accessible to all subdivision residents — a documented amenity distinguishing this community from nearby no-access subdivisions. No lots in the community have direct lake frontage; all access is via the common boat ramp and dock. HOA dues are $110/month.", "847 Lake View Road is a through-street lot of 0.25 acres, approximately 0.35 miles from the community boat ramp. The school zone is average for Spartanburg County. FEMA Zone X is confirmed for the entire lot — the lot does not touch the lake. BMW Manufacturing is approximately 17 miles southwest. No environmental hazards or noise contours are identified. The immediate neighborhood is stable owner-occupied with no documented reinvestment or decline signals."], "factors": [{"id": "A", "label": "Deeded HOA community water access (boat ramp and dock, 0.35 miles)"}, {"id": "B", "label": "HOA dues $110/month"}, {"id": "C", "label": "Through-street location"}, {"id": "D", "label": "FEMA Zone X (entire lot — no lake adjacency)"}, {"id": "E", "label": "Average school district"}, {"id": "F", "label": "Direct lake frontage (not present — distractor)"}, {"id": "G", "label": "Mountain or scenic view"}], "classification_options": ["Positive", "Negative", "Neutral", "Market-Dependent"], "min_rationale_chars": 20, "teaching_points": ["Teaching Point 1 — Community access is Positive but must be identified at the correct tier. Factor A is Positive because deeded HOA water access commands a documented premium over no-access alternatives in the Lake Bowen area. However, this tier is categorically below direct frontage — not equivalent to it. Students who classify Factor A identically to direct waterfront are conflating tiers; students who classify it as Neutral or Negative are undervaluing a genuine documented market amenity.", "Teaching Point 2 — Zone X for the full lot is a direct consequence of the tier position. Because this lot has no lake frontage, the entire lot is in Zone X — there is no Zone AE exposure. This contrasts directly with Scenario 1, where direct frontage brought Zone AE on the rear lot portion. Students who compare this to Scenario 1 learn that the waterfront tier position determines both the access premium and the flood designation simultaneously.", "Teaching Point 3 — Direct frontage distractor tests tier discipline from the second direction. Scenario 1 tested whether students would incorrectly add community access when direct frontage was present. This scenario tests the reverse: students must not identify direct frontage (Factor F) when only community access exists. The analytical obligation is precise tier identification — and the evidence must specifically support whichever tier is identified."]}'::jsonb,
  '{"factors": {"A": {"present": true, "classification": "Positive", "rationale": "Deeded community access is a documented market premium relative to no-access subdivisions in the Lake Bowen area. A Positive — but a categorically different and lower tier than direct waterfront."}, "B": {"present": true, "classification": "Market-Dependent", "rationale": "HOA dues at $110/month cover the community boat ramp and dock. Some buyers accept this as the reasonable cost of lake access; others are deterred. Market-Dependent requires paired sales from comparable community-access structures."}, "C": {"present": true, "classification": "Negative", "rationale": "Through-street with no cul-de-sac — a modest Negative relative to lower-traffic configurations in a lake community context where buyers often seek quiet residential settings."}, "D": {"present": true, "classification": "Positive", "rationale": "Zone X confirmed for the full lot, consistent with no direct lake frontage. No flood insurance requirement — a Positive for both market analysis and lender underwriting."}, "E": {"present": true, "classification": "Neutral", "rationale": "Average-performing zone with no documented premium — Neutral in both primary residential and second-home market contexts."}, "F": {"present": false}, "G": {"present": false}}}'::jsonb
FROM scenarios s
JOIN scenario_categories sc ON sc.id = s.category_id
JOIN module_sections ms ON ms.id = sc.section_id
JOIN section_fields f ON f.section_id = ms.id AND f.field_key = 'factor_analysis'
WHERE sc.code = 'M2-S5-C6'
  AND s.order_index = 2;

