  (scenario_id, field_id, answer_text, field_options_override, model_data)
SELECT
  s.id,
  f.id,
  '',
  '{"subject": {"address_summary": "412 Keowee Shores Drive, Salem, SC 29676", "subject_summary": "3BR/2.5BA · 2,200 SF · 2012-built SFR · Keowee Shores", "context_label": "Specialty Context", "context_text": "Specialty appraisal — Lake Keowee community property. Lake Keowee is a Duke Energy reservoir in Oconee County — one of the Upstate''s premier residential lake markets. Keowee Shores has three defined lot tiers: direct waterfront with private dock (Tier 1, ~45 lots), deeded boat slip assignment with community access but no direct frontage (Tier 2, ~85 lots), and standard residential with community greenspace only (Tier 3, ~90 lots). The subject is a Tier 1 direct waterfront lot."}, "location_profile": ["Keowee Shores is a gated residential community on Lake Keowee with approximately 220 homes across three defined tiers. Lake Keowee is a clear-water Duke Energy reservoir with deep water access, long lake views, and premium market positioning in the Upstate residential market. Direct waterfront lots at Keowee command documented premiums over both Tier 2 and Tier 3 lots within the same community — the tier structure is reflected in the original developer pricing and supported by resale market evidence.", "412 Keowee Shores Drive is a Tier 1 direct waterfront lot with approximately 95 feet of lake frontage and a covered dock slip. Community HOA dues are $425/month covering a 24-hour gate, road maintenance, and common area amenities. FEMA Zone AE covers the rear lot portion adjacent to the lake; the structure is in Zone X. The Oconee County school zone is average with no documented premium. Commercial services are approximately 12 miles away in Westminster. The primary buyer pool is second-home and retirement buyers from the Charlotte, Atlanta, and Greenville markets."], "factors": [{"id": "A", "label": "Direct Lake Keowee waterfront (95 ft frontage, covered dock — Tier 1)"}, {"id": "B", "label": "FEMA Zone AE (rear lot, lake adjacency)"}, {"id": "C", "label": "Gated community with 24-hour security"}, {"id": "D", "label": "HOA dues $425/month"}, {"id": "E", "label": "Remote location / limited services (~12 miles to Westminster)"}, {"id": "F", "label": "Average school district (no documented premium)"}, {"id": "G", "label": "FEMA Zone X (structure location)"}, {"id": "H", "label": "Deeded boat slip assignment (Tier 2 — not present at this Tier 1 lot)"}, {"id": "I", "label": "Mountain or scenic view distinct from lake view"}], "classification_options": ["Positive", "Negative", "Neutral", "Market-Dependent"], "min_rationale_chars": 20, "teaching_points": ["Teaching Point 1 — Tier position within a tiered community is the defining specialty identification. Factor A must be identified at the correct tier: Tier 1 direct waterfront with a covered dock. The community has Tier 2 and Tier 3 lots that are analytically distinct. A Tier 2 boat slip distractor (Factor H) is included because students may confuse the two. The appraiser''s obligation is to establish which tier the subject occupies — and that determination must be supported by the specific physical characteristics described in the location profile.", "Teaching Point 2 — Premium markets have negatives that must be identified. Factors B, D, and E are all present Negatives or Market-Dependent factors in a scenario dominated by positives. Students who identify only the waterfront positive and omit the service distance, Zone AE, and HOA cost are producing an incomplete locational profile. High-value lake markets are not exempt from the obligation to identify all present factors.", "Teaching Point 3 — HOA dues classification requires market evidence, not intuition. Factor D is Market-Dependent at $425/month because buyer acceptance of premium HOA costs in gated lake communities genuinely varies — some buyers price it as standard; others resist it as a constraint on affordability. Students who classify it as Positive because ''the amenities justify the cost'' are applying personal judgment rather than market evidence. The correct answer is Market-Dependent until paired sales from comparable Tier 1 Keowee communities establish the direction."]}'::jsonb,
  '{"factors": {"A": {"present": true, "classification": "Positive", "rationale": "Tier 1 direct waterfront with a covered dock is the highest-value tier in a community with three defined price strata. Documented resale premiums over Tier 2 and Tier 3 lots establish the Positive classification."}, "B": {"present": true, "classification": "Negative", "rationale": "Zone AE on the rear lot portion triggers mandatory flood insurance. A Negative that is standard for Tier 1 lots in the Lake Keowee market — the insurance cost is a real carrying cost that constrains the buyer pool modestly."}, "C": {"present": true, "classification": "Positive", "rationale": "Gated access with 24-hour security is a standard amenity expectation in the premium Lake Keowee market — a Positive that supports the community''s market positioning."}, "D": {"present": true, "classification": "Market-Dependent", "rationale": "At $425/month, dues represent meaningful carrying cost. Some buyers accept this as standard in gated lake communities; others are deterred. Market-Dependent requires paired sales from comparable Tier 1 Keowee communities."}, "E": {"present": true, "classification": "Negative", "rationale": "A 12-mile service radius is a documented Negative for buyers requiring daily convenience access — a constraint present even in the premium Lake Keowee market."}, "F": {"present": true, "classification": "Neutral", "rationale": "Average Oconee County zone with no documented buyer premium — Neutral in both primary residential and second-home market contexts."}, "G": {"present": true, "classification": "Positive", "rationale": "Zone X for the structure reduces flood risk to the improvements — a partial positive that coexists with Zone AE on the rear lot portion."}, "H": {"present": false}, "I": {"present": false}}}'::jsonb
FROM scenarios s
JOIN scenario_categories sc ON sc.id = s.category_id
JOIN module_sections ms ON ms.id = sc.section_id
JOIN section_fields f ON f.section_id = ms.id AND f.field_key = 'factor_analysis'
WHERE sc.code = 'M2-S5-C6'
  AND s.order_index = 3;

