-- Scenario 4: 1234 Hampton Street, Greenville — Hampton Station STR + ADU Urban Infill
-- Category M2-S5-C6 #4 · difficulty 'basic'
-- ─────────────────────────────────────────────────────
INSERT INTO scenarios
  (category_id, order_index, difficulty, title, scenario_text)
SELECT id, 4,
  'basic',
  '1234 Hampton Street, Greenville — Hampton Station STR + ADU Urban Infill',
  'You are performing a specialty locational analysis at 1234 Hampton Street, Greenville, SC 29601. The subject is 3BR/2BA · 1,480 SF · 1938-built SFR (renovated 2021) · Hampton Station District. Specialty appraisal — urban infill property with two interacting specialty characteristics: (1) the property is in the City of Greenville STR overlay zone with current STR licensing available; and (2) a legally permitted detached garage ADU currently generates rental income. The appraiser must identify how locational factors interact with both the STR potential and the ADU rental value. Section 5 — Locational Influence — requires you to identify which locational factors are present at the subject, classify each as Positive, Negative, Neutral, or Market-Dependent based on the location profile evidence and the specialty framework, and write a brief market-supported rationale for each classification. Specialty assignments require the appraiser to identify the relevant specialty characteristics first (waterfront tier, ADU, STR, mountain market, etc.) and then analyze every locational factor through the lens of those characteristics simultaneously. Distractor factors that are not present must be left unchecked, and each rationale must cite specific evidence and connect the factor to the relevant specialty framework.'
FROM scenario_categories WHERE code = 'M2-S5-C6';

INSERT INTO model_answers
  (scenario_id, field_id, answer_text, field_options_override, model_data)
SELECT
  s.id,
  f.id,
  '',
  '{"subject": {"address_summary": "1234 Hampton Street, Greenville, SC 29601", "subject_summary": "3BR/2BA · 1,480 SF · 1938-built SFR (renovated 2021) · Hampton Station District", "context_label": "Specialty Context", "context_text": "Specialty appraisal — urban infill property with two interacting specialty characteristics: (1) the property is in the City of Greenville STR overlay zone with current STR licensing available; and (2) a legally permitted detached garage ADU currently generates rental income. The appraiser must identify how locational factors interact with both the STR potential and the ADU rental value."}, "location_profile": ["The subject is a renovated bungalow with a detached garage ADU in the Hampton Station district, approximately 0.9 miles from Main Street and 1.2 miles from Prisma Health''s downtown Greenville medical campus. The Hampton Station district has experienced documented reinvestment since 2014 — permit records show rising investment activity and MLS data shows increasing median prices over the past 4 years. The Swamp Rabbit Trail is 0.3 miles east. The City of Greenville STR overlay zone covers this address.", "1234 Hampton Street is a through-street lot of 0.15 acres with a 22-foot setback. The detached ADU (420 SF) is currently rented to a Prisma Health employee at market rate. An STR license for the main structure is currently available pending conditional use approval under the overlay zone. The school zone is below-average for Greenville County. FEMA Zone X is confirmed. A mixed-use commercial corridor is 0.4 miles north on Stone Avenue with restaurants and retail."], "factors": [{"id": "A", "label": "Prisma Health / downtown employment proximity (1.2–1.4 miles)"}, {"id": "B", "label": "Swamp Rabbit Trail access (0.3 miles east)"}, {"id": "C", "label": "STR overlay zone (licensing currently available)"}, {"id": "D", "label": "Legal ADU (permitted, income-producing, current tenant)"}, {"id": "E", "label": "Improving neighborhood trajectory (documented, 2014-present)"}, {"id": "F", "label": "Below-average school district"}, {"id": "G", "label": "Through-street location"}, {"id": "H", "label": "FEMA Zone X"}, {"id": "I", "label": "Stone Avenue mixed-use corridor proximity (0.4 miles)"}, {"id": "J", "label": "Lake or water amenity"}, {"id": "K", "label": "Airport noise contour"}], "classification_options": ["Positive", "Negative", "Neutral", "Market-Dependent"], "min_rationale_chars": 20, "teaching_points": ["Teaching Point 1 — STR and ADU are distinct specialty characteristics requiring independent analysis. Factor C (STR licensing) and Factor D (legal ADU) are separate use rights driven by overlapping but distinct locational factors. The STR value is driven by Factors A, B, and amenity proximity; the ADU value is driven primarily by employment proximity (Factor A). Students who analyze only one specialty characteristic are providing an incomplete consulting product — the client needs both lenses addressed.", "Teaching Point 2 — Multiple positives in a specialty urban scenario are analytically legitimate. Seven of the nine present factors are Positive or better. Students conditioned to expect balanced factor distributions may be tempted to reclassify some positives. The obligation is accurate classification based on evidence — not symmetry in the factor list. A well-located urban specialty property can and does produce a predominantly positive locational profile.", "Teaching Point 3 — Mixed-use corridor is Market-Dependent even in a favorable trajectory context. Factor I is Market-Dependent because buyer and tenant response to corridor proximity is genuinely split — the improving trajectory of the corridor does not convert a split response into a Positive. Students who default Positive for any corridor that is improving are conflating trajectory with current buyer response to commercial character."]}'::jsonb,
  '{"factors": {"A": {"present": true, "classification": "Positive", "rationale": "Medical and downtown employment proximity at under 1.5 miles is the primary rental demand driver for both the ADU tenant and the STR guest market — a Positive supporting both specialty characteristics simultaneously."}, "B": {"present": true, "classification": "Positive", "rationale": "Trail access within 0.3 miles is a documented Positive for both long-term professional renters and STR guests in the Greenville urban market."}, "C": {"present": true, "classification": "Positive", "rationale": "Current STR licensing availability under the City overlay zone is a Positive — a current use right with documented income value in the Greenville STR market."}, "D": {"present": true, "classification": "Positive", "rationale": "A legally permitted income-producing ADU is a distinct value component driven directly by the location''s employment proximity — a Positive that compounds with Factor A."}, "E": {"present": true, "classification": "Positive", "rationale": "Documented reinvestment over 4+ years with rising median prices is an improving trajectory classification supported by objective market evidence."}, "F": {"present": true, "classification": "Negative", "rationale": "Below-average school zone constrains the owner-occupant resale pool — a Negative for long-term hold value analysis regardless of strong rental and STR demand."}, "G": {"present": true, "classification": "Negative", "rationale": "Through-street with moderate residential traffic — a modest Negative that slightly constrains the residential appeal for both owner-occupants and long-term tenants."}, "H": {"present": true, "classification": "Positive", "rationale": "Zone X confirmed — no flood insurance requirement supports both residential marketability and lender underwriting."}, "I": {"present": true, "classification": "Market-Dependent", "rationale": "Corridor proximity is a lifestyle convenience positive for some tenant and STR segments; others discount the commercial character. Market-Dependent reflects this genuine split in buyer and tenant response."}, "J": {"present": false}, "K": {"present": false}}}'::jsonb
FROM scenarios s
JOIN scenario_categories sc ON sc.id = s.category_id
JOIN module_sections ms ON ms.id = sc.section_id
JOIN section_fields f ON f.section_id = ms.id AND f.field_key = 'factor_analysis'
WHERE sc.code = 'M2-S5-C6'
  AND s.order_index = 4;

