-- Scenario 5: 2218 Glassy Mountain Road, Landrum — Blue Ridge Foothills with Active STR
-- Category M2-S5-C6 #5 · difficulty 'intermediate'
-- ─────────────────────────────────────────────────────
INSERT INTO scenarios
  (category_id, order_index, difficulty, title, scenario_text)
