  'intermediate',
  '2218 Glassy Mountain Road, Landrum — Blue Ridge Foothills with Active STR',
  'You are performing a specialty locational analysis at 2218 Glassy Mountain Road, Landrum, SC 29356. The subject is 3BR/2BA · 1,780 SF · 2006-built SFR · Blue Ridge Foothills. Specialty appraisal — Blue Ridge foothills property with two interacting specialty characteristics: (1) mountain and seasonal recreational market positioning; and (2) an active STR license under Landrum township rules. The client is a lender financing a second-home purchase. The appraiser must address seasonal demand patterns, mountain location attributes, and how the STR license interacts with locational factors in this specialty market. Section 5 — Locational Influence — requires you to identify which locational factors are present at the subject, classify each as Positive, Negative, Neutral, or Market-Dependent based on the location profile evidence and the specialty framework, and write a brief market-supported rationale for each classification. Specialty assignments require the appraiser to identify the relevant specialty characteristics first (waterfront tier, ADU, STR, mountain market, etc.) and then analyze every locational factor through the lens of those characteristics simultaneously. Distractor factors that are not present must be left unchecked, and each rationale must cite specific evidence and connect the factor to the relevant specialty framework.'
FROM scenario_categories WHERE code = 'M2-S5-C6';

INSERT INTO model_answers
  (scenario_id, field_id, answer_text, field_options_override, model_data)
SELECT
  s.id,
  f.id,
  '',
  '{"subject": {"address_summary": "2218 Glassy Mountain Road, Landrum, SC 29356", "subject_summary": "3BR/2BA · 1,780 SF · 2006-built SFR · Blue Ridge Foothills", "context_label": "Specialty Context", "context_text": "Specialty appraisal — Blue Ridge foothills property with two interacting specialty characteristics: (1) mountain and seasonal recreational market positioning; and (2) an active STR license under Landrum township rules. The client is a lender financing a second-home purchase. The appraiser must address seasonal demand patterns, mountain location attributes, and how the STR license interacts with locational factors in this specialty market."}, "location_profile": ["The subject is located on Glassy Mountain Road in the Blue Ridge foothills near Landrum, approximately 28 miles north of downtown Greenville. The area is a second-home and seasonal-use market with buyer demand driven by mountain views, outdoor recreation access, and proximity to Greenville and Spartanburg. Foothills Trail access is approximately 1.5 miles from the subject. The primary buyer pool includes regional primary residents who commute and second-home buyers from the Charlotte and Atlanta markets.", "2218 Glassy Mountain Road is a 0.85-acre lot with partial Blue Ridge mountain views from the rear deck. SC-14 runs approximately 0.3 miles south — periodically audible from the front of the property during peak hours. The property is served by private well and septic. Commercial services are approximately 10 miles away. The local school zone is a small rural district with limited programming. FEMA Zone X is confirmed. The property is currently licensed as an STR under Landrum township rules and has documented rental history."], "factors": [{"id": "A", "label": "Partial Blue Ridge mountain views (from rear deck)"}, {"id": "B", "label": "Foothills Trail / outdoor recreation access (~1.5 miles)"}, {"id": "C", "label": "Active STR license (Landrum township, documented rental history)"}, {"id": "D", "label": "Seasonal / second-home market demand (Charlotte/Atlanta buyers)"}, {"id": "E", "label": "SC-14 highway noise (audible from front, ~0.3 miles south)"}, {"id": "F", "label": "Private well and septic (no municipal utilities)"}, {"id": "G", "label": "Remote location / limited services (~10 miles)"}, {"id": "H", "label": "Small rural school district (limited programming)"}, {"id": "I", "label": "FEMA Zone X"}, {"id": "J", "label": "Ski-in/ski-out access"}, {"id": "K", "label": "Direct waterfront"}], "classification_options": ["Positive", "Negative", "Neutral", "Market-Dependent"], "min_rationale_chars": 20, "teaching_points": ["Teaching Point 1 — Seasonal demand is Market-Dependent, not automatically Positive. Factor D requires careful classification. The second-home buyer segment is a genuine positive demand source, but the seasonal market character may be a negative for primary residential buyers who require year-round community infrastructure. Market-Dependent is the analytically honest answer until paired sales from comparable foothills communities establish the direction for this specific submarket.", "Teaching Point 2 — Partial views require accurate description for comparable selection. Factor A is Positive but the partial extent of the views is analytically significant. In the Blue Ridge foothills specialty market, view quality and extent drive material value differences among comparable properties — unobstructed panoramic, partial framed, partial obstructed, and no view are distinct conditions that affect adjustment analysis. Students who classify any mountain view as identically Positive regardless of extent are losing a precision that is essential for defensible comparable selection.", "Teaching Point 3 — STR license and seasonal demand interact but are analytically independent. Factor C (STR license) and Factor D (seasonal demand) both relate to the short-term rental use but address different dimensions. The STR license is a current use right; the seasonal demand is the market context that gives the license its income value. Both must be identified independently — and the interaction between them strengthens the STR thesis in a way that neither factor alone fully captures."]}'::jsonb,
  '{"factors": {"A": {"present": true, "classification": "Positive", "rationale": "Partial mountain views from the rear deck are a documented Positive in the Blue Ridge foothills market — though the partial extent of the views must be noted accurately for comparable selection, as it distinguishes this from unobstructed panoramic view properties."}, "B": {"present": true, "classification": "Positive", "rationale": "Trail access within 1.5 miles is a documented positive amenity driver in the foothills second-home and STR markets — supports both seasonal buyer demand and STR guest attraction."}, "C": {"present": true, "classification": "Positive", "rationale": "An active STR license with rental history is a Positive — a current use right with demonstrated income value in a market where STR demand from regional visitors is documented."}, "D": {"present": true, "classification": "Market-Dependent", "rationale": "Seasonal second-home demand is Market-Dependent — the Charlotte and Atlanta buyer segment is a genuine positive driver, but primary residential buyers seeking year-round community infrastructure may view the seasonal market character as a negative. Direction requires paired sales from comparable foothills communities."}, "E": {"present": true, "classification": "Negative", "rationale": "SC-14 traffic periodically audible at 0.3 miles is a Negative residential amenity concern — present even in the mountain specialty market context."}, "F": {"present": true, "classification": "Market-Dependent", "rationale": "In a rural mountain market where private utilities are the norm, Market-Dependent is appropriate — primary residential buyers may resist; rural lifestyle and second-home buyers accept it as characteristic."}, "G": {"present": true, "classification": "Negative", "rationale": "A 10-mile service distance is a Negative for buyers evaluating daily convenience — present even in the second-home and STR specialty context."}, "H": {"present": true, "classification": "Negative", "rationale": "Limited programming relative to county alternatives is a Negative for family buyers — less analytically prominent in a second-home STR context but still a present factor constraining the primary residential resale pool."}, "I": {"present": true, "classification": "Positive", "rationale": "Zone X confirmed."}, "J": {"present": false}, "K": {"present": false}}}'::jsonb
FROM scenarios s
JOIN scenario_categories sc ON sc.id = s.category_id
JOIN module_sections ms ON ms.id = sc.section_id
JOIN section_fields f ON f.section_id = ms.id AND f.field_key = 'factor_analysis'
WHERE sc.code = 'M2-S5-C6'
  AND s.order_index = 5;

