INSERT INTO model_answers
  (scenario_id, field_id, answer_text, field_options_override, model_data)
SELECT
  s.id,
  f.id,
  '',
  '{"subject": {"address_summary": "318 Waterside Court, Chesnee, SC 29323", "subject_summary": "3BR/2BA · 1,940 SF · 2015-built SFR · Waterside at Lake Blalock", "context_label": "Specialty Context", "context_text": "Specialty appraisal — Lake Blalock community property with deeded HOA water access. The specialty characteristics are: (1) deeded community lake access in a second-home and vacation market; and (2) an HOA covenant that restricts short-term rental stays to a maximum of 30 days per year. The client intends personal vacation use with periodic STR income. The appraiser must address how the HOA STR restriction interacts with the locational factors and the client''s intended use."}, "location_profile": ["Waterside at Lake Blalock is a residential community of approximately 110 homes near Lake Blalock in northern Spartanburg County. The community has deeded HOA lake access via a maintained community boat ramp and dock — all residents have access rights, but no lots have direct lake frontage. HOA dues are $180/month. The HOA covenants restrict short-term rental activity to a maximum of 30 days per year — a documented restriction enforced by the HOA board.", "318 Waterside Court is a cul-de-sac lot of 0.28 acres, approximately 0.45 miles from the community boat ramp. FEMA Zone X is confirmed for the entire lot. The school zone is average for Spartanburg County. The subject is approximately 8 miles from downtown Spartanburg. No environmental hazards or noise contours are identified. The neighborhood trajectory is stable with no documented reinvestment or decline signals in recent permit records."], "factors": [{"id": "A", "label": "Deeded HOA community water access (boat ramp and dock, 0.45 miles)"}, {"id": "B", "label": "HOA STR restriction (30-day annual cap)"}, {"id": "C", "label": "HOA dues $180/month"}, {"id": "D", "label": "Cul-de-sac location"}, {"id": "E", "label": "Average school district"}, {"id": "F", "label": "FEMA Zone X (entire lot)"}, {"id": "G", "label": "Stable trajectory (no documented momentum in either direction)"}, {"id": "H", "label": "Direct lake frontage (not present — distractor)"}, {"id": "I", "label": "Airport noise contour"}], "classification_options": ["Positive", "Negative", "Neutral", "Market-Dependent"], "min_rationale_chars": 20, "teaching_points": ["Teaching Point 1 — HOA STR restriction is a Negative, not Market-Dependent. Factor B is Negative because the 30-day annual cap represents a documented, covenant-based constraint on a use right that the client specifically intends to exercise. Unlike Market-Dependent factors where buyer response is split, this restriction is objectively limiting — it applies to all owners regardless of their preference. Students who classify it as Market-Dependent because some buyers accept the restriction are misapplying the Market-Dependent classification, which requires genuine split in buyer response, not merely variable acceptance of a documented constraint.", "Teaching Point 2 — Community access and HOA dues are analytically independent. Factor A (community access) is Positive; Factor C (dues) is Market-Dependent. They are both products of the HOA structure but address different aspects — the amenity value and the cost structure. Collapsing them into a single HOA factor loses a distinction that matters for the client, who is specifically evaluating the relationship between access value and cost burden.", "Teaching Point 3 — Stable trajectory is Neutral in a vacation home specialty context. Factor G describes stability without momentum. In a vacation home submarket, stability without appreciation potential may be a neutral condition for buyers seeking both recreational use and capital appreciation. Students who default Positive for stability in any market are confusing absence of decline with presence of investment opportunity."]}'::jsonb,
  '{"factors": {"A": {"present": true, "classification": "Positive", "rationale": "Deeded community access is a documented market premium over no-access alternatives in Lake Blalock area subdivisions — a Positive at the community access tier."}, "B": {"present": true, "classification": "Negative", "rationale": "The 30-day annual cap materially constrains the client''s STR income strategy. A documented covenant restriction trending toward prohibition is a Negative — not Market-Dependent — because the direction is determinable: the restriction limits the use right regardless of individual buyer acceptance of that limitation."}, "C": {"present": true, "classification": "Market-Dependent", "rationale": "HOA dues at $180/month cover the boat ramp and dock. Some buyers accept this as the cost of lake access; others are deterred. Market-Dependent requires paired sales from comparable community-access structures."}, "D": {"present": true, "classification": "Positive", "rationale": "Cul-de-sac terminus — a consistently positive configuration with no specialty context complications."}, "E": {"present": true, "classification": "Neutral", "rationale": "Average zone with no documented premium — Neutral in both primary residential and vacation home contexts."}, "F": {"present": true, "classification": "Positive", "rationale": "Zone X confirmed for the full lot — consistent with no direct lake frontage. No flood insurance requirement."}, "G": {"present": true, "classification": "Neutral", "rationale": "No documented reinvestment or decline signals is a Neutral trajectory classification — not an improving opportunity but not a deteriorating risk either."}, "H": {"present": false}, "I": {"present": false}}}'::jsonb
FROM scenarios s
JOIN scenario_categories sc ON sc.id = s.category_id
JOIN module_sections ms ON ms.id = sc.section_id
JOIN section_fields f ON f.section_id = ms.id AND f.field_key = 'factor_analysis'
WHERE sc.code = 'M2-S5-C6'
  AND s.order_index = 6;

