INSERT INTO model_answers
  (scenario_id, field_id, answer_text, field_options_override, model_data)
SELECT
  s.id,
  f.id,
  '',
  '{"subject": {"address_summary": "4417 Hartwell Shore Drive, Anderson, SC 29625", "subject_summary": "3BR/2BA · 1,920 SF · 1998-built SFR (updated 2018) · Hartwell Shores", "context_label": "Specialty Context", "context_text": "Specialty appraisal — Lake Hartwell direct waterfront property. Lake Hartwell is a U.S. Army Corps of Engineers reservoir on the SC/GA border — one of the Southeast''s largest recreational lakes. Specialty characteristics: (1) direct waterfront with a Corps-permitted dock; and (2) partially obstructed lake views. Multiple conflicting locational factors are present including Zone AE, highway noise, and view quality issues that complicate the positive waterfront classification."}, "location_profile": ["Lake Hartwell Shores is a residential community on the South Carolina shoreline of Lake Hartwell in Anderson County, approximately 6 miles from downtown Anderson. Lake Hartwell covers approximately 56,000 acres and supports one of the Southeast''s most active recreational boating markets. Direct waterfront lots on Hartwell command documented premiums. The subject has approximately 78 feet of direct lake frontage with a Corps-permitted covered dock.", "4417 Hartwell Shore Drive is a through-street lot of 0.38 acres. Lake views from the subject are partially obstructed by a mature tree line on the adjacent lot — views are present but not fully unobstructed. FEMA Zone AE covers the rear lot area adjacent to the lake; the structure is in Zone X. SC-187, which crosses a nearby causeway, runs approximately 0.2 miles north — traffic noise including recreational boat trailer traffic is periodically audible. The school zone is average for Anderson County. No HOA or community dues apply."], "factors": [{"id": "A", "label": "Direct Lake Hartwell waterfront (78 ft frontage, Corps-permitted dock)"}, {"id": "B", "label": "FEMA Zone AE (rear lot, lake adjacency — flood insurance required)"}, {"id": "C", "label": "Partially obstructed lake views (adjacent tree line)"}, {"id": "D", "label": "SC-187 causeway traffic noise (~0.2 miles, periodic recreational traffic)"}, {"id": "E", "label": "Through-street location"}, {"id": "F", "label": "Average school district"}, {"id": "G", "label": "FEMA Zone X (structure location)"}, {"id": "H", "label": "Fully unobstructed panoramic lake view (not present — distractor)"}, {"id": "I", "label": "HOA community amenity"}], "classification_options": ["Positive", "Negative", "Neutral", "Market-Dependent"], "min_rationale_chars": 20, "teaching_points": ["Teaching Point 1 — Partially obstructed views are Market-Dependent, not equivalent to unobstructed views. Factor C requires precision. The profile documents partial obstruction from an adjacent tree line — not fully unobstructed and not fully blocked. Distractor H (fully unobstructed view) tests whether students will overstate the view quality. Market-Dependent is appropriate because buyer response to partial obstruction genuinely varies and paired sales from Lake Hartwell must establish the direction. Students who check H instead of or alongside C are misrepresenting the view condition.", "Teaching Point 2 — Three simultaneous negatives coexist with the dominant waterfront positive. Factors B, D, and E are all present Negatives that must be identified regardless of how strong the waterfront premium is. In advanced specialty lake scenarios, the analytical challenge is not finding the positive — it is disciplining the identification to capture all negatives that reduce the degree of the positive. The waterfront premium does not eliminate the Zone AE insurance cost, the causeway noise, or the through-street character.", "Teaching Point 3 — Corps permit status is a specific waterfront characteristic. The Corps-permitted dock is explicitly identified in Factor A because Lake Hartwell docks require U.S. Army Corps of Engineers permits — a regulatory condition specific to federal reservoir lakes. Students who identify a dock without noting the Corps permit status are missing a condition that affects both the dock''s legal validity and its value contribution. In federal reservoir markets, permitted vs. unpermitted dock status is a material distinction."]}'::jsonb,
  '{"factors": {"A": {"present": true, "classification": "Positive", "rationale": "Direct frontage with a Corps-permitted dock is the defining specialty characteristic and primary Positive. Documented premiums for direct waterfront over community-access lots in the Lake Hartwell market establish the classification."}, "B": {"present": true, "classification": "Negative", "rationale": "Zone AE on the rear lot portion triggers mandatory flood insurance. A Negative coexisting independently with the waterfront Positive — standard in the Lake Hartwell direct waterfront market."}, "C": {"present": true, "classification": "Market-Dependent", "rationale": "Partial view obstruction from an adjacent tree line produces split buyer response — some buyers find partial framing acceptable; others require clear sightlines and will negotiate or decline. Market-Dependent requires paired sales distinguishing partial and unobstructed view lots."}, "D": {"present": true, "classification": "Negative", "rationale": "SC-187 causeway traffic audible at 0.2 miles — including recreational boat trailer activity — is a Negative residential amenity concern independent of the waterfront positive."}, "E": {"present": true, "classification": "Negative", "rationale": "Through-street with moderate residential traffic — a modest Negative in a lake community context."}, "F": {"present": true, "classification": "Neutral", "rationale": "Average Anderson County zone with no documented premium — Neutral in the second-home and recreational buyer market context."}, "G": {"present": true, "classification": "Positive", "rationale": "Zone X for the structure reduces flood risk to the improvements — a partial positive that coexists with Zone AE on the rear lot."}, "H": {"present": false}, "I": {"present": false}}}'::jsonb
FROM scenarios s
JOIN scenario_categories sc ON sc.id = s.category_id
JOIN module_sections ms ON ms.id = sc.section_id
JOIN section_fields f ON f.section_id = ms.id AND f.field_key = 'factor_analysis'
WHERE sc.code = 'M2-S5-C6'
  AND s.order_index = 7;

