FROM scenario_categories WHERE code = 'M2-S5-C6';

INSERT INTO model_answers
  (scenario_id, field_id, answer_text, field_options_override, model_data)
SELECT
  s.id,
  f.id,
  '',
  '{"subject": {"address_summary": "847 Overbrook Drive, Greenville, SC 29605", "subject_summary": "3BR/2BA + ADU · 2,040 SF (main) / 480 SF (ADU) · 1955-built SFR (renovated 2020) · Overbrook", "context_label": "Specialty Context", "context_text": "Specialty appraisal — primary residence with a legally permitted attached garage ADU in the Overbrook neighborhood. The specialty characteristic is the income-producing ADU, which is legally permitted under Greenville County zoning and currently generates rental income from a healthcare worker tenant. The appraisal must address how locational factors interact with both the primary residential value and the ADU income potential through two simultaneous analytical lenses."}, "location_profile": ["The subject is a renovated single-family residence with a legally permitted attached garage ADU in the Overbrook neighborhood, approximately 1.6 miles from downtown Greenville and 1.3 miles from Prisma Health''s downtown medical campus. The Overbrook corridor has experienced documented reinvestment since 2016 — rising prices, active permit activity, and new independent retail on Augusta Road 0.4 miles north. The Swamp Rabbit Trail is approximately 0.6 miles east.", "847 Overbrook Drive is a through-street lot of 0.18 acres. The ADU (480 SF attached garage apartment) is currently rented at market rate to a Prisma Health employee. Augusta Road — a four-lane urban arterial — is 0.4 miles north, providing walkable retail and dining access. The school zone is below-average for Greenville County. FEMA Zone X is confirmed. A vacant commercial building with visible deferred maintenance occupies the adjacent parcel to the east."], "factors": [{"id": "A", "label": "Prisma Health employment proximity (~1.3 miles — primary ADU demand driver)"}, {"id": "B", "label": "Downtown Greenville proximity (~1.6 miles)"}, {"id": "C", "label": "Swamp Rabbit Trail access (~0.6 miles)"}, {"id": "D", "label": "Legal ADU (permitted, income-producing, current healthcare worker tenant)"}, {"id": "E", "label": "Improving neighborhood trajectory (Overbrook, documented 2016-present)"}, {"id": "F", "label": "Adjacent vacant/blighted commercial building (east parcel)"}, {"id": "G", "label": "Below-average school district"}, {"id": "H", "label": "Augusta Road walkable access (retail/dining, 0.4 miles)"}, {"id": "I", "label": "FEMA Zone X"}, {"id": "J", "label": "Through-street location"}, {"id": "K", "label": "Airport noise contour"}, {"id": "L", "label": "Lake or waterfront amenity"}], "classification_options": ["Positive", "Negative", "Neutral", "Market-Dependent"], "min_rationale_chars": 20, "teaching_points": ["Teaching Point 1 — ADU value is driven by the same locational factors as long-term rental demand. Factor A (Prisma Health proximity) directly supports the ADU''s current rental income — the healthcare worker tenant was drawn to the location for employment access. In an ADU appraisal, the appraiser must identify and classify locational factors through two simultaneous lenses: primary residential value and ADU income value. Factor A is Positive for both dimensions, which is analytically significant because it means the location supports both uses without conflict.", "Teaching Point 2 — Adjacent blight constrains both the primary value and the ADU marketability. Factor F affects both the owner-occupant residential appeal of the primary structure and the tenant experience for the ADU — constraining tenant quality, turnover risk, and the eventual owner-occupant resale pool. Students who identify Factor F as a Negative for the primary use only, without noting its ADU impact, are providing a partial dual-lens analysis.", "Teaching Point 3 — Multiple positives in a specialty ADU scenario reflect genuine locational strength. Eight of the ten present factors are Positive. Students who force a more balanced distribution are introducing false precision. The Overbrook location is genuinely well-positioned for both primary residential and ADU income use — and the ADU specialty characteristic amplifies the positive locational factors by creating a second value stream tied directly to the location''s employment and amenity access."]}'::jsonb,
  '{"factors": {"A": {"present": true, "classification": "Positive", "rationale": "Medical employment at 1.3 miles is the primary rental demand driver for the ADU tenant and supports stable occupancy — a Positive for both primary residential marketability and ADU income value simultaneously."}, "B": {"present": true, "classification": "Positive", "rationale": "Downtown proximity supports both owner-occupant demand and the broader rental market from which ADU tenants and primary tenants are drawn."}, "C": {"present": true, "classification": "Positive", "rationale": "Trail access within 0.6 miles is a documented Positive for professional renters and urban lifestyle buyers — supports both primary residential and ADU tenant demand."}, "D": {"present": true, "classification": "Positive", "rationale": "A legally permitted income-producing ADU is a distinct value component driven directly by the location''s employment proximity — a Positive compounding with Factor A."}, "E": {"present": true, "classification": "Positive", "rationale": "Documented reinvestment over 4+ years with rising median prices and new retail is a strong improving trajectory — a Positive for both long-term hold value and ADU income growth potential."}, "F": {"present": true, "classification": "Negative", "rationale": "Adjacent blight at zero separation is a documented Negative affecting both the primary residential appeal and the ADU tenant experience — constraining tenant quality and the owner-occupant resale pool."}, "G": {"present": true, "classification": "Negative", "rationale": "Below-average school zone constrains the owner-occupant resale pool and is a Negative for long-term exit strategy regardless of strong ADU demand."}, "H": {"present": true, "classification": "Positive", "rationale": "Walkable retail and dining access within 0.4 miles is a Positive for professional renters and lifestyle-oriented owner-occupants in this urban corridor."}, "I": {"present": true, "classification": "Positive", "rationale": "Zone X confirmed."}, "J": {"present": true, "classification": "Negative", "rationale": "Through-street with moderate traffic — a modest Negative constraining residential appeal for both owner-occupants and long-term tenants."}, "K": {"present": false}, "L": {"present": false}}}'::jsonb
FROM scenarios s
JOIN scenario_categories sc ON sc.id = s.category_id
JOIN module_sections ms ON ms.id = sc.section_id
