INSERT INTO model_answers
  (scenario_id, field_id, answer_text, field_options_override, model_data)
SELECT
  s.id,
  f.id,
  '',
  '{"subject": {"address_summary": "3318 Keowee Peninsula Drive, Salem, SC 29676", "subject_summary": "4BR/3.5BA · 3,200 SF · 2018-built SFR · Keowee Peninsula Club", "context_label": "Specialty Context", "context_text": "Specialty appraisal — Lake Keowee direct waterfront property in a private gated club community. Four interacting specialty characteristics: (1) direct waterfront with a 2-slip covered dock; (2) an active Oconee County STR registration; (3) HOA covenants permitting STR use with a 7-night minimum stay requirement; and (4) a seasonal resort market with pronounced second-home demand from the Charlotte, Atlanta, and Greenville markets. The appraiser must address all four specialty interactions comprehensively."}, "location_profile": ["Keowee Peninsula Club is a gated luxury community on Lake Keowee in Oconee County with approximately 85 homes. Approximately 35 lots have direct waterfront with private docks; the remaining lots have community lake access via club amenities. The club facility includes a pool, tennis courts, and a boat launch. HOA dues are $575/month. Community CC&Rs permit short-term rental use with a 7-night minimum stay — stays shorter than 7 nights are prohibited. An Oconee County STR registration is on file for the subject with documented rental history.", "3318 Keowee Peninsula Drive is a direct waterfront lot with approximately 110 feet of lake frontage, fully unobstructed lake views, and a covered 2-slip private dock. FEMA Zone AE covers the rear lot portion adjacent to the lake; the structure is in Zone X. The seasonal second-home demand for Lake Keowee is highly pronounced — Charlotte, Atlanta, and Greenville buyers are the primary market. Commercial services are approximately 15 miles away. The Oconee County school zone is average with no documented premium. No highway noise or environmental hazards are identified."], "factors": [{"id": "A", "label": "Direct Lake Keowee waterfront (110 ft, fully unobstructed views, 2-slip covered dock)"}, {"id": "B", "label": "FEMA Zone AE (rear lot, lake adjacency — flood insurance required)"}, {"id": "C", "label": "Club community amenities (pool, tennis, boat launch)"}, {"id": "D", "label": "HOA dues $575/month"}, {"id": "E", "label": "HOA 7-night minimum stay requirement (STR constraint)"}, {"id": "F", "label": "Active Oconee County STR registration (7-night minimum applies)"}, {"id": "G", "label": "Seasonal / second-home demand (Charlotte/Atlanta/Greenville buyers — pronounced)"}, {"id": "H", "label": "Remote location / limited services (~15 miles)"}, {"id": "I", "label": "Average school district (no documented premium)"}, {"id": "J", "label": "FEMA Zone X (structure location)"}, {"id": "K", "label": "Gated community with security"}, {"id": "L", "label": "Deeded community boat slip (Tier 2 — not present at this direct waterfront lot)"}, {"id": "M", "label": "Mountain or scenic view distinct from lake view"}], "classification_options": ["Positive", "Negative", "Neutral", "Market-Dependent"], "min_rationale_chars": 20, "teaching_points": ["Teaching Point 1 — STR license and HOA minimum stay interact to create a constrained use right. Factor E (7-night minimum) and Factor F (active STR registration) must be analyzed together. The STR registration is active but the minimum stay constraint limits it to the weekly vacation rental market — eliminating the higher-yield weekend and short-stay segments. This makes Factor F Market-Dependent rather than Positive: the use right exists but its income value depends on whether the weekly Lake Keowee rental market is sufficient to justify the premium pricing needed to offset the limited booking windows.", "Teaching Point 2 — Seasonal demand at Lake Keowee is Positive, not Market-Dependent. Unlike the Blue Ridge foothills scenario (S5) where seasonal demand is Market-Dependent, Lake Keowee''s second-home market is Positive because the buyer pool from three major metros is documented, deep, and stable — a level of market evidence that supports a directional classification. Students must distinguish between markets where seasonal demand evidence establishes direction (Keowee) and markets where it requires further paired sales to establish direction (foothills). The difference is the quality and depth of the available market evidence.", "Teaching Point 3 — Expert specialty analysis requires holding all four characteristics simultaneously. This scenario requires the appraiser to analyze 11 present factors through four simultaneous lenses: waterfront tier, STR use right, HOA covenant constraints, and seasonal market dynamics. Students who analyze any single specialty characteristic and omit the others are providing a partial consulting product. Expert-level specialty appraisal is defined by the ability to identify and classify every present factor accurately while tracking how each factor interacts with each specialty characteristic — producing an analysis that a sophisticated client can act on with confidence."]}'::jsonb,
  '{"factors": {"A": {"present": true, "classification": "Positive", "rationale": "Tier 1 direct waterfront with unobstructed views and a 2-slip covered dock is the most premium waterfront configuration in the Keowee market — the defining Positive specialty characteristic."}, "B": {"present": true, "classification": "Negative", "rationale": "Zone AE on the rear lot triggers mandatory flood insurance — a Negative carrying cost standard in the Lake Keowee direct waterfront tier."}, "C": {"present": true, "classification": "Positive", "rationale": "Club amenities are a documented expectation and Positive in the premium Lake Keowee market — buyers in this segment price community amenities as part of the overall location premium."}, "D": {"present": true, "classification": "Market-Dependent", "rationale": "At $575/month, HOA dues are a meaningful carrying cost. Some buyers in the premium lake market accept this as standard; others are deterred. Market-Dependent requires paired sales from comparable gated Keowee communities."}, "E": {"present": true, "classification": "Negative", "rationale": "The 7-night minimum eliminates the weekend and short-stay STR segments. This is a documented covenant constraint — a Negative for the investor seeking maximum STR income flexibility, though less restrictive than a full STR prohibition."}, "F": {"present": true, "classification": "Market-Dependent", "rationale": "The STR registration is active but constrained by the 7-night minimum. Market-Dependent rather than Positive because the use right is real but limited — direction requires analysis of weekly vacation rental demand in the Lake Keowee STR market to establish net income value."}, "G": {"present": true, "classification": "Positive", "rationale": "The Lake Keowee second-home market has a documented, deep, and stable buyer pool from three major metro markets — a Positive seasonal demand classification supported by transaction volume evidence in the Keowee market."}, "H": {"present": true, "classification": "Negative", "rationale": "A 15-mile service distance is a Negative even in the premium lake resort market — buyers accept it as a tradeoff for the waterfront location, but it constrains the primary residential buyer pool."}, "I": {"present": true, "classification": "Neutral", "rationale": "Average Oconee County zone with no documented premium — Neutral in a market dominated by second-home and resort buyers for whom school zone is not a primary selection criterion."}, "J": {"present": true, "classification": "Positive", "rationale": "Zone X for the structure reduces flood risk to the improvements — a partial positive coexisting with Zone AE on the rear lot."}, "K": {"present": true, "classification": "Positive", "rationale": "Gated access is a standard expectation and documented Positive in the premium Keowee resort community market."}, "L": {"present": false}, "M": {"present": false}}}'::jsonb
FROM scenarios s
JOIN scenario_categories sc ON sc.id = s.category_id
JOIN module_sections ms ON ms.id = sc.section_id
